// 存储空间统计：用于「查看存储空间」页面的类型定义
type StorageUsageCategory = {
  key: string;
  label: string;
  bytes: number;
  color: string;
};

type StorageUsageSummary = {
  totalBytes: number;
  categories: StorageUsageCategory[];
};

type RoleRelationType =
  | 'stranger'
  | 'friend'
  | 'family'
  | 'colleague'
  | 'lover'
  | 'ex'
  | 'schoolmate'
  | 'roommate'
  | 'boss_subordinate'
  | 'other';

type RoleRelationship = {
  otherRoleId: string;
  relation: RoleRelationType;
  // 供模型理解用的补充说明，例如“发小”“青梅竹马”等（不会直接显示在关系图上）
  note?: string;
  // 玩家可自定义的人物关系文案，用于关系图中显示（例如“旧情复燃的前任”“亦师亦友的搭档”）
  customLabel?: string;
};

type StoryWorldbookEntry = {
  id: string;
  title: string;
  content: string;
  keyword?: string;
  // 是否启用该条目作为提示词（默认为启用）
  enabled?: boolean;
};

type StoryWorldbook = {
  id: string;
  name: string;
  // 是否启用整本世界书作为提示词（默认为启用）
  enabled?: boolean;
  entries: StoryWorldbookEntry[];
};

type GeneratedNpc = {
  id: string;
  name: string;
  gender?: 'male' | 'female' | 'other' | '';
  mbti?: string; // MBTI人格类型（例如：INTJ、ENFP等）
  avatarUrl?: string;
  age?: number | null;
  // 角色设定页需要展示的结构化信息
  occupation?: string; // 职业
  interests?: string; // 兴趣（多个用顿号/逗号分隔）
  dealbreakers?: string; // 雷点（多个用顿号/逗号分隔）
  callMe?: string; // NPC 对玩家的称呼（在这个角色面前）
  personality?: string;
  identity?: string;
  persona?: string;
  quote?: string; // 角色语录（符合角色人设的简短语句）
  intro?: string; // 角色简单个人介绍
  wechatNickname?: string;
  wechatSignature?: string;
  wechatRegion?: string;
  wechatId?: string;
  relationWithRole?: string;
  relationWithRoleGraphLabel?: string; // 与主角的关系标签（用于graphLabel，NPC视角）
  relationFromRole?: string; // 主角视角的关系描述（从主角视角看这个NPC）
  relationFromRoleGraphLabel?: string; // 主角视角的关系标签（从主角视角看这个NPC）
  relationWithPlayer?: string;
  acquaintanceWithPlayer?: string; // 与你的相识经历（用“我”，玩家第一人称）
  worldbookSummary?: string;
  relationsToOthers?: Array<{
    targetIndex: number;
    relation: RoleRelationType | 'stranger';
    // graphLabel：短标签，用于关系图箭头中间展示（例如"前上司""发小"）
    graphLabel?: string;
    // note：更完整的关系说明，从当前 NPC 视角出发，供人设/底部详情使用
    note?: string;
  }>;
};

type NpcRelationsCompletionIssue = {
  fromIndex: number; // 缺失/需要改写的方向起点（数组下标）
  toIndex: number; // 缺失/需要改写的方向终点（数组下标）
  reason: 'missing' | 'sameNote'; // missing: 另一方向记录缺失；sameNote: 双向 note 被判定为完全相同
};

type NpcRelationsCompletionReport = {
  issues: NpcRelationsCompletionIssue[];
};

