type WechatMomentsCommentReply = {
  id: string;
  author: string;
  content: string;
  time: string;
  replyTo?: string;
  /** 支持“回复的回复”（第三层） */
  replies?: WechatMomentsCommentReply[];
};

type WechatMomentsComment = {
  id: string;
  author: string;
  content: string;
  time: string;
  replies: WechatMomentsCommentReply[];
};

type WechatMomentsDemoPost = {
  id: string;
  avatarLabel: string;
  name: string;
  /** 用于同步“发布者头像”为对应微信联系人/角色头像 */
  authorType?: 'player' | 'role';
  authorRoleId?: string;
  /** 无文案则为「仅图片」动态 */
  text?: string;
  time: string;
  /** 可选：定位/地点（用于显示在发布时间戳右侧） */
  location?: string;
  /** 可选：发布时间戳（毫秒）；超过 7 天时用于展示完整日期时间 */
  postedAt?: number;
  images: string[];
  /** 与 images 一一对应的每张图片描述词（用于“点击图片翻转查看”） */
  imageDescs?: string[];
  likesCount: number;
  likedByMe: boolean;
  /** 点赞用户昵称（不包含玩家自己；由 likedByMe / 交互动态追加玩家昵称） */
  likedUsers: string[];
  comments: WechatMomentsComment[];
};

type WechatMomentsPublishMode = 'player' | 'role';

type WechatMomentsPublishLikeInput = {
  atSec: number;
  type: 'like';
  actorRoleId: string;
};

// 回复节点（支持任意深度）
type WechatMomentsPublishReplyInput = {
  atSec: number;
  type: 'reply';
  replyKey: string; // stable id key（用于定时插入）
  actorRoleId: string;
  replyContent: string;
  replyToActorRoleId?: string; // 用于渲染 “回复@XXX：” 前缀
  replies?: WechatMomentsPublishReplyInput[]; // 子回复（任意深度）
};

type WechatMomentsPublishCommentInput = {
  atSec: number;
  type: 'comment';
  commentKey: string; // stable id key（用于定时插入）
  actorRoleId: string;
  commentContent: string;
  replies?: WechatMomentsPublishReplyInput[];
};

type WechatMomentsPublishInteractionInput =
  | WechatMomentsPublishLikeInput
  | WechatMomentsPublishCommentInput;

type WechatMomentsPublishPostInput = {
  authorType: WechatMomentsPublishMode;
  authorRoleId?: string;
  text: string;
  location?: string;
  /** 图片朋友圈：每张图只输出描述词 desc；url 会被前端替换为默认预览图 */
  images?: Array<{ desc: string }>;
  interactions: WechatMomentsPublishInteractionInput[];
};

type WechatMomentsPublishResponse = {
  posts: WechatMomentsPublishPostInput[];
};

const WECHAT_MOMENTS_GENERATED_POSTS_KEY = 'mini-ai-phone.wechat-moments-generated-posts-v1';
const loadGeneratedMomentsPosts = (): WechatMomentsDemoPost[] => {
  try {
    const raw = appStorage.getItem(WECHAT_MOMENTS_GENERATED_POSTS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? (parsed as WechatMomentsDemoPost[]) : [];
  } catch {
    return [];
  }
};

const saveGeneratedMomentsPosts = (posts: WechatMomentsDemoPost[]) => {
  try {
    appStorage.setItem(WECHAT_MOMENTS_GENERATED_POSTS_KEY, JSON.stringify(posts));
  } catch {
    // ignore
  }
};

/** 单聊：会话开启「主动发朋友圈」时并入系统提示 */
const WECHAT_INLINE_MOMENTS_APPENDIX_PRIVATE = `【微信朋友圈（本段生效：玩家已为当前会话开启「主动发朋友圈」）】
在本轮输出的**绝对末尾**（在正常微信气泡、[DANMAKU] 段、[HEART_LANGUAGE] 段、<<MUTUAL_FRIEND_CHAIN>>…<<END_MUTUAL_FRIEND_CHAIN>>、<<AUTO_VOICE_CALL:true/false>> 全部之后），另起一段且仅一段输出：
<<WECHAT_MOMENTS>>
{"shouldPost":false,"text":"","location":""}
<<END_WECHAT_MOMENTS>>

规则：
- 将中间那一行替换为**单行合法 JSON**（不要 markdown、不要换行、不要解释）。也可使用单元素数组，如 [{"shouldPost":false,"text":"","location":""}]，效果相同。
- shouldPost 为 true 时：
  - 若要发“文字/图片+文字”，text 填 1～2 句口语文案
  - 若要发“单发图片”，也可以让 text 为空字符串 ""（仅图片由后续朋友圈生成请求根据上下文决定）；location 仍可选
- 绝大多数轮次应为 false。
- 结合人设、情绪、本轮对话（含继续回复、已读不回、忙完回复、主动发消息等场景），判断此刻是否值得顺手发条朋友圈。
- location 分级地址用「·」，如 福建·厦门·黄厝海滩；不需要则可用空字符串。
`;

/** 群聊：每项对应一名成员，须带 roleId */
const WECHAT_INLINE_MOMENTS_APPENDIX_GROUP = `【微信朋友圈（本段生效：玩家已为当前群聊开启「主动发朋友圈」）】
在本轮输出的**绝对末尾**（在正常群聊气泡、[DANMAKU] 段、[HEART_LANGUAGE] 段、<<MUTUAL_FRIEND_CHAIN>>…、<<AUTO_VOICE_CALL:true/false>> 全部之后），另起一段且仅一段输出：
<<WECHAT_MOMENTS>>
[{"roleId":"某成员角色ID","shouldPost":false,"text":"","location":""}]
<<END_WECHAT_MOMENTS>>

规则：
- 中间为**单行合法 JSON 数组**（不要 markdown、不要换行、不要解释）。
- **每项必须包含 roleId**：与上方「群成员列表」中的角色 ID（StoryRole.id）一致，表示**该成员**是否发这条朋友圈。
- 只为本轮确实用 <<SPEAKER:...>> 说过话的成员填写条目；未开口的成员不要编造，或 shouldPost 为 false。
- shouldPost 为 true 时：
  - 若要发“文字/图片+文字”，text 填 1～2 句口语文案
  - 若要发“单发图片”，也可以让 text 为空字符串 ""（仅图片由后续朋友圈生成请求根据上下文决定）；location 仍可选
- 多数成员多数轮次应为 false。
- location 分级地址用「·」；不需要则可用空字符串。
`;

const buildWeChatInlineMomentsAppendix = (isGroup: boolean): string =>
  isGroup ? WECHAT_INLINE_MOMENTS_APPENDIX_GROUP : WECHAT_INLINE_MOMENTS_APPENDIX_PRIVATE;

const formatMomentsLocationPersist = (location?: string): string => {
  const raw = String(location || '').trim();
  if (!raw) return '';
  return raw
    .split(/[·•\-/，、,\s]+/g)
    .map((v) => v.trim())
    .filter(Boolean)
    .join('·');
};

