type ApiConfig = {
  baseUrl: string;
  apiKey: string;
  model: string;
};

// 功能维度
type FeatureKey = 'chat' | 'chatlogCard' | 'danmaku' | 'heartLanguage' | 'moments';

// 单个接口配置
type SingleApiConfig = {
  baseUrl: string;
  apiKey: string;
  model: string;
};

// 多接口配置结构
type MultiApiConfig = {
  default: SingleApiConfig;
  overrides: Partial<Record<FeatureKey, SingleApiConfig>>;
};

// 提示词功能开关
type PromptFeatureFlags = {
  danmaku: boolean;
  heartLanguage: boolean;
  chatlogCard: boolean;
};

const API_STORAGE_KEY = 'mini-ai-phone.api-config';
const API_STORAGE_KEY_V2 = 'mini-ai-phone.api-config.v2';

// 加载多接口配置（优先读 v2，没有则从旧版迁移）
const loadMultiApiConfig = (): MultiApiConfig => {
  try {
    const v2Raw = appStorage.getItem(API_STORAGE_KEY_V2);
    if (v2Raw) {
      const parsed = JSON.parse(v2Raw) as Partial<MultiApiConfig>;
      return {
        default: parsed.default || { baseUrl: '', apiKey: '', model: '' },
        overrides: parsed.overrides || {}
      };
    }
  } catch {
    // ignore
  }

  // 尝试从旧版迁移
  try {
    const oldRaw = appStorage.getItem(API_STORAGE_KEY);
    if (oldRaw) {
      const oldParsed = JSON.parse(oldRaw) as Partial<ApiConfig>;
      const migrated: MultiApiConfig = {
        default: {
          baseUrl: oldParsed.baseUrl ?? '',
          apiKey: oldParsed.apiKey ?? '',
          model: oldParsed.model ?? ''
        },
        overrides: {}
      };
      return migrated;
    }
  } catch {
    // ignore
  }

  return {
    default: { baseUrl: '', apiKey: '', model: '' },
    overrides: {}
  };
};

// 按功能获取 API 配置
const getApiConfigFor = (feature: FeatureKey): SingleApiConfig | null => {
  const multi = loadMultiApiConfig();
  const featureCfg = multi.overrides[feature];
  const defaultCfg = multi.default;

  const pick = (c: SingleApiConfig | undefined): SingleApiConfig | null => {
    if (!c) return null;
    if (!c.baseUrl || !c.model) return null;
    return c;
  };

  // 优先用该功能的独立配置，否则回退到 default
  return pick(featureCfg) || pick(defaultCfg);
};

// 兼容旧版加载函数
const loadApiConfig = (): ApiConfig => {
  const multi = loadMultiApiConfig();
  return {
    baseUrl: multi.default.baseUrl,
    apiKey: multi.default.apiKey,
    model: multi.default.model
  };
};

const stripAnonymousQaAtMentions = (text: string): string => {
  const src = String(text || '');
  return src
    .replace(/[＠@]\s*[A-Za-z0-9_\-\u4e00-\u9fa5·•.]{1,24}/g, '')
    .replace(/定向\s*[＠@]\s*[A-Za-z0-9_\-\u4e00-\u9fa5·•.]{1,24}/g, '')
    .replace(/[＠@]/g, '')
    .replace(/\s{2,}/g, ' ')
    .replace(/^[，。,.、\s]+|[，。,.、\s]+$/g, '')
    .trim();
};

/** 定向匿问：由剧情角色生成主回答（提问者匿名，角色不得指认提问者）；可选带人脉 NPC 的短评楼层 */
const fetchStoryRoleDirectedAnonymousQaAnswer = async (
  cfg: SingleApiConfig,
  args: {
    roleDisplayName: string;
    personaSummary: string;
    worldbookBlock: string;
    relationsBlock: string;
    memoryBlock: string;
    questionTitle: string;
    questionBody: string;
    /** 非空时模型可输出 npcChimes */
    relationNpcChimeRoster?: string;
    allowedNpcRoleIds?: string[];
    playerWechatNickname?: string;
  }
): Promise<{
  content: string;
  npcChimes: Array<{ roleId: string; content: string }>;
  randomNetizenChimes: Array<{ authorName: string; content: string }>;
}> => {
  const hasChimeRoster =
    !!String(args.relationNpcChimeRoster || '').trim() && (args.allowedNpcRoleIds?.length ?? 0) > 0;

  const chimeBlock = hasChimeRoster
    ? `

【答主人脉里可能一起刷匿问区的熟人】（下列 roleId 必须 **逐字一致** 才可写入 npcChimes；共 0～3 条）
${args.relationNpcChimeRoster}

npcChimes 规则：
- 每条是「该熟人刷到这条匿问动态后顺口插一句」：短、口语、人设要与上表摘要及记忆摘录一致；可与主回答调侃接梗，但不要写成第二段长篇主回答。
- 同样遵守铁律：不得指认、揣测匿名提问者是谁。
- 若当前没有合适熟人开口，npcChimes 填 []。

【随机匿名网友】（与上表熟人 **无关** 的路人/粉丝/乐子人，**必须** 同时生成）
- 输出 **randomNetizenChimes：至少 2 条、至多 4 条**。每条仅含 authorName（网感昵称，勿与上表任何显示名相同或雷同）与 content（短句、吃瓜围观、玩梗，不知提问者是谁）。
- 即使 npcChimes 为空，randomNetizenChimes 仍须 ≥2 条。

输出 JSON：{"content":"主回答 1～8 句","npcChimes":[{"roleId":"…","content":"…"}],"randomNetizenChimes":[{"authorName":"…","content":"…"}]}`
    : `

请写一条主回答：口语化、适合匿问区；约 1～8 句。

【随机匿名网友】须同时输出 randomNetizenChimes：**1～3 条**，为路人/粉丝式短评（authorName 网感昵称 + content），与剧情熟人无关、不知提问者是谁。

严格只输出 JSON：{"content":"正文，不要 markdown","randomNetizenChimes":[{"authorName":"…","content":"…"}]}`;

  const prompt = `你在微信「匿问我答」里被 **匿名用户** 定向提问。@你的内容如下（对方在平台上完全匿名，你不知道 ta 是谁）。

【铁律】
- 不得在回答中猜测、暗示或点破提问者是谁；禁止「我猜是你」「你是不是——」等表述。
- 禁止引用「只有你和某个熟人独处时才知道的具体私密事件」来对照这条匿名提问是谁发的。
- 请把问题当作**陌生网友的匿名纸条**，真诚作答；可运用人设、世界书、你平常的说话习惯。
- 可参考下方「与聊天对象的长期记忆、近期对话」调节**语感与亲疏**（像对熟人说话可以更软），但叙述上不要显得你**认出了**本条提问者。
- 可参考「人脉关系网」自然带出口语里对圈内朋友的称呼习惯；${hasChimeRoster ? '并可按需生成 npcChimes 中好友的接话；randomNetizenChimes 代表不认识你的纯路人网友。' : ''}

【你的角色名】${args.roleDisplayName}
【人设与设定摘要】
${args.personaSummary || '（无）'}
【人设世界书】
${args.worldbookBlock || '（暂无）'}
【人脉关系网】
${args.relationsBlock || '（暂无）'}
【与聊天对象的长期记忆与近期对话】（仅调语气，禁止用于指认本帖提问者身份）
${args.memoryBlock || '（暂无）'}

【匿名提问 · 标题】${args.questionTitle}
【匿名提问 · 正文】${args.questionBody}
${chimeBlock}`;

  const endpointBase = String(cfg.baseUrl).replace(/\/+$/, '');
  const url =
    endpointBase.endsWith('/chat/completions') || endpointBase.endsWith('/completions')
      ? endpointBase
      : `${endpointBase}/chat/completions`;
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      ...(cfg.apiKey ? { Authorization: `Bearer ${cfg.apiKey}` } : {})
    },
    body: JSON.stringify({
      model: cfg.model,
      temperature: 0.85,
      messages: [
        {
          role: 'system',
          content: hasChimeRoster
            ? '你只输出可解析 JSON。你是角色本人在匿问区作答；npcChimes 为圈内好友短接话；randomNetizenChimes 为无关路人网友。绝不指认匿名提问者身份。'
            : '你只输出可解析 JSON。你是角色本人在匿问区作答；须含 randomNetizenChimes 路人围观。绝不指认匿名提问者身份。'
        },
        { role: 'user', content: prompt }
      ]
    })
  });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  const data = await res.json();
  let text = String(data?.choices?.[0]?.message?.content || '').trim();
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  }
  if (!(text.startsWith('{') || text.startsWith('['))) {
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start >= 0 && end > start) text = text.slice(start, end + 1);
  }
  const parsed = JSON.parse(text) as { content?: string; npcChimes?: unknown; randomNetizenChimes?: unknown };
  const out = String(parsed?.content || '').trim();
  if (!out) throw new Error('EMPTY_CONTENT');
  const allowed = new Set(args.allowedNpcRoleIds || []);
  const npcDisplayNames = new Set(
    String(args.relationNpcChimeRoster || '')
      .split('\n')
      .map((line) => {
        const m = line.match(/昵称=([^|]+)/);
        return m ? String(m[1]).trim() : '';
      })
      .filter(Boolean)
  );
  const npcChimes: Array<{ roleId: string; content: string }> = [];
  if (hasChimeRoster && allowed.size > 0 && Array.isArray(parsed?.npcChimes)) {
    for (const c of parsed.npcChimes as any[]) {
      const rid = String(c?.roleId || '').trim();
      const ct = stripAnonymousQaAtMentions(String(c?.content || '').trim());
      if (!rid || !allowed.has(rid) || !ct) continue;
      npcChimes.push({ roleId: rid, content: ct });
      if (npcChimes.length >= 3) break;
    }
  }
  const nickSan = String(args.playerWechatNickname || '').trim();
  const randomNetizenChimes: Array<{ authorName: string; content: string }> = [];
  if (Array.isArray(parsed?.randomNetizenChimes)) {
    let zi = 0;
    for (const c of parsed.randomNetizenChimes as any[]) {
      const ct = stripAnonymousQaAtMentions(String(c?.content || '').trim());
      if (!ct) continue;
      let an = sanitizeAnonymousQaGeneratedNetizenName(String(c?.authorName || '').trim(), zi, nickSan);
      if (npcDisplayNames.has(an)) an = `路人${zi + 1}`;
      randomNetizenChimes.push({ authorName: an, content: ct });
      zi += 1;
      const cap = hasChimeRoster ? 4 : 3;
      if (randomNetizenChimes.length >= cap) break;
    }
  }
  return { content: out, npcChimes, randomNetizenChimes };
};

/** 模型生成的纯网友跟帖：禁止与玩家展示名、「微信昵称（已匿名）」等混淆 */
const sanitizeAnonymousQaGeneratedNetizenName = (name: string, index: number, playerWechatNickname: string): string => {
  let n = String(name || '').trim() || `网友${index + 1}`;
  const pn = String(playerWechatNickname || '').trim();
  if (pn && n === pn) n = `网友${index + 1}`;
  if (/微信昵称/.test(n)) n = `网友${index + 1}`;
  if (/（\s*已匿名\s*）|\(\s*已匿名\s*\)/.test(n)) n = `网友${index + 1}`;
  if (n === '匿名用户' || n === '我') n = `网友${index + 1}`;
  return n;
};

type AnonymousQaNetizenThreadPayload = {
  questionTitle: string;
  questionContent: string;
  playerText: string;
  mode: 'answer' | 'comment';
  threadHint?: string;
  /** 本条主回答正文摘要（便于答主人格互动） */
  answerContentPreview: string;
  answerAuthorName: string;
  answerAuthorRoleId: string | null;
  answerAuthorIsAnonymous: boolean;
  existingComments: Array<{ id: string; authorName: string; content: string }>;
  /** mode=comment 时玩家刚发评论的 id，可作为 parentCommentId */
  playerCommentId?: string | null;
  /** 玩家微信昵称：生成侧禁止冒充；勿写入网友 authorName */
  playerWechatNickname?: string;
  /** 与答主存在人脉关系的 NPC，可下场跟帖（含其记忆/人设摘要） */
  npcRelationRoster?: Array<{ roleId: string; displayName: string; detail: string }>;
};

/** 模型返回的一批跟帖（parent 由前端按 batch 下标与已有 id 解析） */
type AnonymousQaNetizenReplyRaw = {
  authorName: string;
  content: string;
  /** 回复已有评论 id（须已通过校验） */
  parentCommentId: string | null;
  replyToBatchIndex: number | null;
  asAnswerAuthor: boolean;
  /** 若与 npcRelationRoster 中 roleId 匹配，则使用该剧情角色身份发帖 */
  npcAuthorRoleId?: string | null;
};

const fetchAnonymousQaNetizenRepliesThreaded = async (
  cfg: ApiConfig,
  payload: AnonymousQaNetizenThreadPayload
): Promise<AnonymousQaNetizenReplyRaw[]> => {
  const validParentIds = new Set<string>();
  payload.existingComments.forEach((c) => validParentIds.add(c.id));
  if (payload.playerCommentId) validParentIds.add(payload.playerCommentId);

  const listBlock =
    payload.existingComments.length > 0
      ? payload.existingComments
          .map(
            (c) =>
              `- id=${c.id} | 作者：${c.authorName} | 正文：${String(c.content).slice(0, 120)}${String(c.content).length > 120 ? '…' : ''}`
          )
          .join('\n')
      : '（当前主回答下尚无评论）';

  const playerBlock =
    payload.mode === 'comment' && payload.playerCommentId
      ? `玩家刚发的评论 id=${payload.playerCommentId}，正文：${payload.playerText}\n${payload.threadHint ? `补充：${payload.threadHint}` : ''}`
      : `玩家刚发的主回答正文：${payload.playerText}`;

  const playerNick = String(payload.playerWechatNickname || '').trim();
  const 答主Block =
    payload.answerAuthorRoleId === 'me'
      ? `⚠️ **本层主回答由玩家本人发布**。系统禁止你代替玩家发言：所有 replies 的 asAnswerAuthor **必须** 为 false；不得生成任何「玩家第一人称」或让读者以为是玩家刚发的楼；不得使用与玩家微信名相同或极易混淆的 authorName。`
      : payload.answerAuthorRoleId
        ? `本层主回答作者（答主）显示名：「${payload.answerAuthorName}」，为站内好友身份（非玩家）。你可生成少量 asAnswerAuthor=true 的回复，表现为答主在帖子里跟玩家或其它网友自然互动；此类条目的 authorName 可填与答主显示名一致或略称。`
        : `本层主回答作者（答主）显示名：「${payload.answerAuthorName}」${payload.answerAuthorIsAnonymous ? '（匿名展示）' : ''}，非玩家。若答主非站内好友 id，可将 ta 视为网友人格：可以生成 asAnswerAuthor=true 的跟帖，延续该行文风格与立场，与玩家或其它网友对话。`;

  const npcRosterBlock =
    payload.npcRelationRoster && payload.npcRelationRoster.length > 0
      ? `
【可下场的站内 NPC】（与答主存在人脉；均有独立人设与记忆摘录，回复须贴合其人设）
${payload.npcRelationRoster
  .map(
    (r) =>
      `- roleId=${r.roleId} | 显示名「${r.displayName}」 | ${r.detail}`
  )
  .join('\n')}

- 若有适合人物，可让其中若干条使用 **npcAuthorRoleId** 字段（字符串，须与上表某一 roleId **完全一致**），表示该 NPC 在评论区与玩家、网友或答主互动。
- **禁止** npcAuthorRoleId 填「${payload.answerAuthorRoleId || ''}」或与答主同 id（答主请仍用 asAnswerAuthor=true，勿与 NPC 字段混用）。
- 每条带 npcAuthorRoleId 的回复，authorName 须与上表显示名一致或为合理略称。
- 网友与 NPC、NPC 与 NPC 之间均可互怼，不必只回复玩家。
- **注意**：下方「重要」里对**随机路人网友**的条数要求是强制的，不可只生成 NPC。`
      : '';

  const hasNpcRoster = !!(payload.npcRelationRoster && payload.npcRelationRoster.length > 0);
  const randomNetizenMixRule = hasNpcRoster
    ? `
**【必须混杂随机匿名网友】** 匿问区有大量**不认识答主**的路人，本批 **绝不能** 全是圈内 NPC。
- **至少 3 条** replies 须同时满足：npcAuthorRoleId=null、asAnswerAuthor=false，authorName 为**网感随机昵称**（零食梗、乐子人、纯粉丝、杠精路人等），且 **禁止** 与上方【可下场的站内 NPC】任一显示名相同或明显雷同。
- 带 npcAuthorRoleId 的条数 **必须少于** 上述纯路人网友条数（路人为主，熟人为辅）。
- 纯路人口吻：围观吃瓜、玩梗起哄、脑补八卦；**不要**写成经纪人/发小/家人那种「明显圈内工作关系」的口气（那是 NPC 专场）。`
    : '';

  const impersonationBan = `**硬性禁令（违反则整条作废思维）**：
- 你**无权**代替玩家回复：replies 中每一条必须是第三方「网友」身份；不得写玩家口吻替玩家互动。
- authorName **禁止**与玩家微信展示名相同或刻意模仿：玩家昵称为「${playerNick || '（界面未配置）'}」时尤其留意。
- authorName **禁止**含「微信昵称」「已匿名」等易与玩家匿名展示混淆的字样；禁止用「匿名用户」冒充玩家楼。
- 仅非玩家答主才可偶发 asAnswerAuthor=true（见下方说明）；**玩家主答时 asAnswerAuthor 全程 false**。`;

  const prompt = `你是「匿我问答」评论区导演。严格只输出 JSON，不要 markdown，不要解释。

${impersonationBan}

讨论目标问题：
标题：${payload.questionTitle}
正文：${payload.questionContent}

本主回答楼层已有评论（只能使用下列真实 id 作为 parentCommentId 来「回复某一楼」；不可编造 id）：
${listBlock}

${playerBlock}

${答主Block}
${npcRosterBlock}

本主回答正文摘要（供答主视角回复时对齐语气）：${payload.answerContentPreview}
${randomNetizenMixRule}

**重要：不要全部只回复玩家。** 请构建立体讨论：
- 一部分回复可以针对玩家刚发内容（parentCommentId=${payload.playerCommentId || '（玩家发的是主回答则用空）'} 或一级跟帖 parentCommentId 空字符串表示与主回答同级）。
- 几条应当是**网友对网友**：parentCommentId 填上面列表里**别的网友**评论的 id；或网友之间抬杠、接梗、补充。
- 允许使用 replyToBatchIndex：若某条想回复**本批 replies 里更早的一条**，填 0～当前下标-1 的整数（不要用负数）。
- 若且仅若答主**不是玩家本人**，可含 0～3 条 asAnswerAuthor=true，表示**答主**下场互动；若答主是玩家，**全部** asAnswerAuthor=false。
- 若上方提供了【可下场的站内 NPC】，可另含 0～4 条带 npcAuthorRoleId 的回复（与 asAnswerAuthor 互斥：同一条只能二选一，优先 npcAuthorRoleId）；**且须满足上文「必须混杂随机匿名网友」的条数**。
- parentCommentId 与 replyToBatchIndex 二选一即可；若同时给出，优先 replyToBatchIndex。

若 parentCommentId 为空字符串 "" 或 null，表示该主回答下的一级评论（与众多跟帖并列挂载在同一 answer 楼层）。

${hasNpcRoster ? '条数随机 6～14，以便同时安排多名路人与少量圈内 NPC。' : '条数随机 2～14。'}${hasNpcRoster ? '其中 **无 npcAuthorRoleId** 的纯网友条须占多数。' : ''} content 简短。禁止出现 @ 或＠符号。

JSON 格式（示例字段名必须一致）：
{"replies":[
  {"authorName":"昵称","content":"…","parentCommentId":"","replyToBatchIndex":null,"asAnswerAuthor":false,"npcAuthorRoleId":null}
]}`;

  const endpointBase = String(cfg.baseUrl).replace(/\/+$/, '');
  const url =
    endpointBase.endsWith('/chat/completions') || endpointBase.endsWith('/completions')
      ? endpointBase
      : `${endpointBase}/chat/completions`;
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      ...(cfg.apiKey ? { Authorization: `Bearer ${cfg.apiKey}` } : {})
    },
    body: JSON.stringify({
      model: cfg.model,
      temperature: 0.92,
      messages: [
        {
          role: 'system',
          content:
            '只输出可被 JSON.parse 解析的一个对象，键为 replies。不得冒充玩家。批内须含大量随机路人网友昵称；若有 NPC 名单，仍必须混杂多数纯网友（npcAuthorRoleId 为空），不能全是 NPC。'
        },
        { role: 'user', content: prompt }
      ]
    })
  });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  const data = await res.json();
  let text = String(data?.choices?.[0]?.message?.content || '').trim();
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  }
  if (!(text.startsWith('{') || text.startsWith('['))) {
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start >= 0 && end > start) text = text.slice(start, end + 1);
  }
  const parsed = JSON.parse(text) as { replies?: unknown };
  const arr = Array.isArray(parsed?.replies) ? parsed.replies : [];
  const rows: AnonymousQaNetizenReplyRaw[] = [];

  const stripImpersonationAuthorName = (name: string, index: number, isAnswerAuthorRow: boolean): string => {
    let n = String(name || '').trim() || `网友${index + 1}`;
    if (playerNick && n === playerNick) n = `网友${index + 1}`;
    if (/微信昵称/.test(n)) n = `网友${index + 1}`;
    if (!isAnswerAuthorRow) {
      if (/（\s*已匿名\s*）|\(\s*已匿名\s*\)/.test(n)) n = `网友${index + 1}`;
      if (n === '匿名用户' || n === '我') n = `网友${index + 1}`;
    }
    return n;
  };

  const rosterIdSet = new Set((payload.npcRelationRoster || []).map((r) => r.roleId));
  const answerAuthorId = payload.answerAuthorRoleId ? String(payload.answerAuthorRoleId) : '';

  arr.forEach((raw: any, i: number) => {
    const content = stripAnonymousQaAtMentions(String(raw?.content || '').trim());
    if (!content) return;

    const npcRidRaw = raw?.npcAuthorRoleId != null ? String(raw.npcAuthorRoleId).trim() : '';
    const npcAllowed =
      !!npcRidRaw &&
      npcRidRaw !== 'me' &&
      (!answerAuthorId || npcRidRaw !== answerAuthorId) &&
      rosterIdSet.has(npcRidRaw);

    let asAnswerAuthor =
      !npcAllowed &&
      raw?.asAnswerAuthor === true &&
      payload.answerAuthorRoleId != null &&
      payload.answerAuthorRoleId !== 'me';
    const pidRaw = raw?.parentCommentId == null ? '' : String(raw.parentCommentId).trim();
    const parentCommentId = pidRaw && validParentIds.has(pidRaw) ? pidRaw : null;
    const batchIdxRaw =
      typeof raw?.replyToBatchIndex === 'number'
        ? raw.replyToBatchIndex
        : typeof raw?.batchParentIndex === 'number'
          ? raw.batchParentIndex
          : null;
    const replyToBatchIndex =
      batchIdxRaw != null && Number.isFinite(batchIdxRaw) && batchIdxRaw >= 0 ? Math.floor(batchIdxRaw) : null;

    let authorName = String(raw?.authorName || '').trim() || `网友${i + 1}`;
    if (npcAllowed) {
      const ro = payload.npcRelationRoster!.find((r) => r.roleId === npcRidRaw);
      authorName = ro?.displayName || authorName;
    } else if (asAnswerAuthor) {
      authorName = payload.answerAuthorName || authorName;
    }
    authorName = stripImpersonationAuthorName(authorName, i, asAnswerAuthor);

    rows.push({
      authorName,
      content,
      parentCommentId,
      replyToBatchIndex,
      asAnswerAuthor,
      npcAuthorRoleId: npcAllowed ? npcRidRaw : null
    });
  });

  return rows;
};

const loadStoryRoles = (): StoryRole[] => {
  try {
    const raw = appStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    const roles = parsed as StoryRole[];

    // 迁移旧存档：早期版本通过“聊天设定页批量生成 NPC”时未写入 npcOfRoleId，
    // 导致角色分组把 NPC 误判为主要角色。这里按“可唯一确定”规则自动回填。
    const roleById = new Map<string, StoryRole>();
    roles.forEach((r) => {
      if (r?.id) roleById.set(r.id, r);
    });
    let migrated = false;
    const nextRoles = roles.map((role) => {
      const hasNpcOwner = !!String(role?.npcOfRoleId || '').trim();
      if (hasNpcOwner) return role;
      const worldbooks = Array.isArray(role?.worldbooks) ? role.worldbooks : [];
      const looksLikeGeneratedNpc = worldbooks.some((wb) =>
        String(wb?.name || '').includes('自动生成 NPC 设定')
      );
      if (!looksLikeGeneratedNpc) return role;

      const relations = Array.isArray(role?.relations) ? role.relations : [];
      const ownerCandidates = relations
        .map((rel) => String(rel?.otherRoleId || '').trim())
        .filter((id) => !!id && id !== role.id)
        .filter((id, idx, arr) => arr.indexOf(id) === idx)
        .filter((id) => {
          const candidate = roleById.get(id);
          if (!candidate) return false;
          // 主角候选必须本身不是已绑定 NPC
          if (String(candidate.npcOfRoleId || '').trim()) return false;
          // 需要存在候选 -> 当前角色的反向关系，避免误匹配
          const rev = Array.isArray(candidate.relations) ? candidate.relations : [];
          return rev.some((r) => String(r?.otherRoleId || '').trim() === role.id);
        });

      if (ownerCandidates.length !== 1) return role;
      migrated = true;
      return {
        ...role,
        npcOfRoleId: ownerCandidates[0]
      };
    });

    if (migrated) {
      appStorage.setItem(STORAGE_KEY, JSON.stringify(nextRoles));
    }
    return nextRoles;
  } catch {
    return [];
  }
};

