const createId = () => {
  if (typeof crypto !== 'undefined' && typeof (crypto as any).randomUUID === 'function') {
    return (crypto as any).randomUUID();
  }
  // 兼容不支持 randomUUID 的环境：时间戳 + 随机数，尽量保持全局唯一
  return `${Date.now().toString(36)}-${Math.random().toString(36).slice(2)}`;
};

// 通讯录：基于“备注/昵称首字”推断拼音首字母（A-Z），用于 26 字母分组
// 说明：
// - 这里不引入第三方拼音库，改用 Intl.Collator 的拼音排序能力 + 常用分界汉字近似映射。
// - 在大多数现代浏览器/移动端 WebView 下，`zh-Hans-u-co-pinyin` 能按拼音排序。
// - 对少数不支持该排序规则的环境，会回退到 `zh`，并尽量稳定输出 A-Z / #。
const PINYIN_INITIAL_BOUNDARIES: Array<{ letter: string; boundary: string }> = [
  { letter: 'A', boundary: '阿' },
  { letter: 'B', boundary: '芭' },
  { letter: 'C', boundary: '擦' },
  { letter: 'D', boundary: '搭' },
  { letter: 'E', boundary: '蛾' },
  { letter: 'F', boundary: '发' },
  { letter: 'G', boundary: '噶' },
  { letter: 'H', boundary: '哈' },
  { letter: 'J', boundary: '击' },
  { letter: 'K', boundary: '喀' },
  { letter: 'L', boundary: '垃' },
  { letter: 'M', boundary: '妈' },
  { letter: 'N', boundary: '拿' },
  { letter: 'O', boundary: '哦' },
  { letter: 'P', boundary: '啪' },
  { letter: 'Q', boundary: '期' },
  { letter: 'R', boundary: '然' },
  { letter: 'S', boundary: '撒' },
  { letter: 'T', boundary: '塌' },
  { letter: 'W', boundary: '挖' },
  { letter: 'X', boundary: '昔' },
  { letter: 'Y', boundary: '压' },
  { letter: 'Z', boundary: '匝' }
];

const getPinyinCollator = (): Intl.Collator => {
  try {
    // 拼音排序（更符合通讯录分组直觉）
    return new Intl.Collator('zh-Hans-u-co-pinyin', { sensitivity: 'base' });
  } catch {
    try {
      return new Intl.Collator('zh', { sensitivity: 'base' });
    } catch {
      // 最差回退：按 Unicode
      return new Intl.Collator(undefined, { sensitivity: 'base' });
    }
  }
};

const CONTACTS_PINYIN_COLLATOR = getPinyinCollator();

const getNameFirstMeaningfulChar = (name: string): string => {
  const s = String(name || '').trim();
  if (!s) return '';
  // 取第一个非空白字符
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (ch && ch.trim()) return ch;
  }
  return s.charAt(0);
};

const getContactSortLetter = (displayName: string): string => {
  const ch = getNameFirstMeaningfulChar(displayName);
  if (!ch) return '#';
  // 英文直接分组
  if (/[A-Za-z]/.test(ch)) return ch.toUpperCase();
  // 数字/符号统一放到 #
  if (/[0-9]/.test(ch)) return '#';

  // 中文/其它：用拼音排序分界汉字近似映射
  try {
    // 若比 A 边界还小，归到 A
    if (CONTACTS_PINYIN_COLLATOR.compare(ch, PINYIN_INITIAL_BOUNDARIES[0].boundary) < 0) {
      return 'A';
    }
    // 依次找“最后一个 <= ch 的边界”
    let result = 'Z';
    for (let i = 0; i < PINYIN_INITIAL_BOUNDARIES.length; i++) {
      const b = PINYIN_INITIAL_BOUNDARIES[i];
      if (CONTACTS_PINYIN_COLLATOR.compare(ch, b.boundary) >= 0) {
        result = b.letter;
      } else {
        break;
      }
    }
    return result;
  } catch {
    return '#';
  }
};

