const splitPrefs = (value: string) => (value || '').split(/[、,，\n]/).map((x) => x.trim()).filter(Boolean);
const parseSingleWithOther = (value: string, options: string[]) => {
  const v = (value || '').trim();
  if (!v) return { selected: '', custom: '' };
  if (v === '其他') return { selected: '其他', custom: '' };
  if (options.includes(v)) return { selected: v, custom: '' };
  return { selected: '其他', custom: v };
};
const parseMultiWithOther = (value: string, options: string[]) => {
  const tokens = splitPrefs(value);
  const preset = tokens.filter((t) => options.includes(t) && t !== '其他');
  const customTokens = tokens.filter((t) => !options.includes(t));
  const hasExplicitOther = tokens.includes('其他');
  if (customTokens.length || hasExplicitOther) preset.push('其他');
  return { preset: Array.from(new Set(preset)), custom: customTokens.join('、') };
};
const buildMultiWithOther = (preset: string[], custom: string) => {
  const base = preset.filter((x) => x !== '其他');
  const final = [
    ...base,
    ...(preset.includes('其他')
      ? custom.trim()
        ? splitPrefs(custom)
        : ['其他']
      : [])
  ];
  return Array.from(new Set(final)).join('、');
};

