const WECHAT_CONTACTS_KEY = 'mini-ai-phone.wechat-contacts';
const RECENT_FORWARD_KEY = 'mini-ai-phone.recent-forward';

// 最近转发记录类型
type RecentForwardItem = {
  chatId: string;
  chatName: string;
  avatarUrl?: string;
  avatarText?: string;
  timestamp: number;
};

type VoiceCallPhase = 'ringing' | 'connected' | 'declined' | 'no_answer';
type VoiceCallToastKind = 'connected' | 'declined' | 'no_answer' | 'hangup';
type VoiceCallMessage = {
  id: string;
  from: 'self' | 'other';
  text: string;
  createdAt: number;
};

// ===== 上下文参考范围（统一口径）=====
const WECHAT_CONTEXT_LIMIT = 50; // 最近微信聊天条数
/** 与 Story 侧 WECHAT_CONTEXT_LINE_CHARS 对齐：记忆区每条未总结消息最大字数 */
const WECHAT_MEMORY_LINE_CHARS = 200;
const VOICE_CALL_CONTEXT_LIMIT = 50; // 最近通话内容条数
const STORY_CONTEXT_LIMIT = 20; // 最近线下剧情条数
const STORY_MOMENT_LIMIT = 5; // 线下关键片段条数

// 加载最近转发记录
const loadRecentForwards = (): RecentForwardItem[] => {
  try {
    const raw = appStorage.getItem(RECENT_FORWARD_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? (parsed as RecentForwardItem[]) : [];
  } catch {
    return [];
  }
};

// 保存最近转发记录
const saveRecentForward = (item: RecentForwardItem) => {
  try {
    const forwards = loadRecentForwards();
    // 移除已存在的相同chatId的记录
    const filtered = forwards.filter(f => f.chatId !== item.chatId);
    // 添加到最前面
    const updated = [item, ...filtered].slice(0, 5); // 最多保存5条
    appStorage.setItem(RECENT_FORWARD_KEY, JSON.stringify(updated));
  } catch (err) {
    console.error('保存最近转发记录失败:', err);
  }
};

const loadWeChatContacts = (): WeChatContact[] => {
  try {
    const raw = appStorage.getItem(WECHAT_CONTACTS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? (parsed as WeChatContact[]) : [];
  } catch {
    return [];
  }
};

const saveWeChatContact = (contact: WeChatContact) => {
  try {
    const contacts = loadWeChatContacts();
    const existingIndex = contacts.findIndex(c => c.roleId === contact.roleId);
    if (existingIndex >= 0) {
      contacts[existingIndex] = contact;
    } else {
      contacts.push(contact);
    }
    appStorage.setItem(WECHAT_CONTACTS_KEY, JSON.stringify(contacts));
  } catch (err) {
    console.error('保存微信联系人失败:', err);
  }
};

// 群聊（本地，仅用于会话列表 & 后续扩展）
type WeChatGroupChat = {
  id: string; // group-xxx
  name: string; // 群聊名称（默认：玩家、角色1、角色2（n））
  memberRoleIds: string[]; // 不含玩家本人
  // 群成员映射（推荐使用）：群内唯一 memberId -> roleId
  // - memberId 建议使用 `${groupId}|${roleId}`，这样跨群也天然不冲突
  // - 兼容旧数据：如果没有 members，则退回 memberRoleIds
  members?: Array<{ memberId: string; roleId: string; nickname?: string }>;
  createdAt: number;
  // 可选：群公告（仅本地，用于提示词和 UI 展示）
  announcement?: string;
  // 可选：玩家对该群的备注（仅玩家可见）
  remark?: string;
  // 可选：玩家在本群单独设置的昵称（仅在当前群聊生效）
  playerNickname?: string;
  // 是否显示群成员昵称（当前版本仅前端展示用）
  showMemberNicknames?: boolean;
  // 群主是否是玩家本人（仅用于控制是否允许编辑群名称/公告/成员）
  ownerIsPlayer?: boolean;
  // 群管理员角色ID列表（后续可扩展为更精细的权限控制）
  adminRoleIds?: string[];
};

const WECHAT_GROUP_CHATS_KEY = 'mini-ai-phone.wechat-group-chats';

const loadWeChatGroupChats = (): WeChatGroupChat[] => {
  try {
    const raw = appStorage.getItem(WECHAT_GROUP_CHATS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? (parsed as WeChatGroupChat[]).filter(Boolean) : [];
  } catch {
    return [];
  }
};

const saveWeChatGroupChats = (groups: WeChatGroupChat[]) => {
  try {
    appStorage.setItem(WECHAT_GROUP_CHATS_KEY, JSON.stringify(groups || []));
  } catch (err) {
    console.error('保存微信群聊失败:', err);
  }
};

// 兼容群聊历史数据：有些地方可能把「memberId=groupId|roleId」误存进 senderRoleId / memberRoleIds。
// 群聊 UI 取头像时只认纯 roleId，因此这里做一次规范化。
const normalizeGroupRoleId = (raw: any): string => {
  const s = String(raw || '').trim();
  if (!s) return '';
  if (s.includes('|')) {
    const parts = s.split('|').map((p) => p.trim()).filter(Boolean);
    const last = parts.length ? parts[parts.length - 1] : '';
    return last || s;
  }
  return s;
};

// 加载微信联系人并转换为聊天列表
const loadWeChatChats = () => {
  // 清理已废弃的内置会话：AI 助手 / 灵感备忘录
  // - 这些会话会造成理解成本与数据噪音；现在改为不再内置。
  // - 这里做一次“尽力清理”（localStorage + IndexedDB），避免它们在旧数据中残留。
  try {
    const onceKey = '__mini_ai_phone_cleanup_builtin_chats_v1__';
    if (!(window as any)[onceKey]) {
      (window as any)[onceKey] = true;
      const legacyChatIds = ['chat-ai', 'chat-notes'];

      for (const chatId of legacyChatIds) {
        try {
          // 聊天消息快照
          appStorage.removeItem(`mini-ai-phone.chat-messages-${chatId}`);
          // 对话记忆（线上）
          appStorage.removeItem(`mini-ai-phone.chat-memories-${chatId}`);
          appStorage.removeItem(`mini-ai-phone.chat-memories-counter-${chatId}`);
          appStorage.removeItem(`mini-ai-phone.chat-memories-counter-${chatId}-last-summary-count`);
          // 未读/清空偏移等展示状态
          appStorage.removeItem(`mini-ai-phone.wechat-chat-last-read-${chatId}`);
          appStorage.removeItem(`mini-ai-phone.wechat-chat-clear-count-${chatId}`);
        } catch {
          // ignore per chat
        }
      }

      // IndexedDB 里也清掉对应会话（不阻塞 UI）
      void (async () => {
        try {
          const db = await openAppDb();
          await Promise.all(
            legacyChatIds.map(
              (chatId) =>
                new Promise<void>((resolve) => {
                  try {
                    const tx = db.transaction(CHAT_MESSAGES_STORE, 'readwrite');
                    const store = tx.objectStore(CHAT_MESSAGES_STORE);
                    store.delete(chatId);
                    tx.oncomplete = () => resolve();
                    tx.onerror = () => resolve();
                    tx.onabort = () => resolve();
                  } catch {
                    resolve();
                  }
                })
            )
          );
        } catch {
          // ignore
        }
      })();
    }
  } catch {
    // ignore
  }

  const contacts = loadWeChatContacts();
  const roles = loadStoryRoles();

  const contactChats = contacts.map(contact => {
    const role = roles.find(r => r.id === contact.roleId);
    if (!role) return null;

    return {
      id: `chat-${contact.roleId}`,
      name: contact.remark || role.wechatNickname || role.name,
      avatarText: role.name.charAt(0),
      avatarUrl: role.avatarUrl,
      lastMessage: '',
      time: '',
      unread: 0,
      roleId: contact.roleId
    };
  }).filter(Boolean) as Array<{
    id: string;
    name: string;
    avatarText: string;
    avatarUrl?: string;
    lastMessage: string;
    time: string;
    unread: number;
    roleId: string;
  }>;

  // 仅保留联系人聊天（已移除内置的「AI 助手」「灵感备忘录」会话）
  const groupChats = loadWeChatGroupChats().map((g) => ({
    id: g.id,
    name: g.name || '群聊',
    avatarText: '群',
    avatarUrl: undefined as any,
    lastMessage: '',
    time: '',
    unread: 0,
    // 用于在群聊页展示成员（不走单聊的 roleId 逻辑）
    memberRoleIds: Array.isArray(g.memberRoleIds) ? g.memberRoleIds : []
  }));
  return [...groupChats, ...contactChats];
};

const mockChats = loadWeChatChats();

// 聊天消息类型
type ChatMessage = {
  id: string;
  from: 'other' | 'self' | 'system';
  text: string;
  time: string;
  // 可选：发送方对应的角色ID（用于群聊中区分具体是哪位NPC说话）
  senderRoleId?: string;
  // 可选：消息的时间戳（用于红包记录等需要按年份统计的场景）
  timestamp?: number;
  greeting?: string; // 打招呼消息（仅系统消息使用）
  voiceDuration?: number; // 语音消息时长（秒），如果存在则表示这是语音消息
  // 如果是表情/表情包消息，text 一般形如 "[表情] 小狗亲亲"，emojiName 保存表情名称，渲染时优先显示对应图片
  emojiName?: string;
  // 如果是红包消息
  redPacketAmount?: number; // 金额（单位：元）
  redPacketNote?: string; // 备注
  // 红包状态：未拆开 / 已领取（仅对含红包的消息生效）
  redPacketStatus?: 'unopened' | 'received';
  // 图片消息：占位预览图 + 文本描述（后续可替换为接入生图API输出的真实图片URL/缩略图）
  imagePreviewUrl?: string;
  imageDesc?: string;
  // 系统消息类型（例如红包领取提示、撤回提示等）
  systemType?: 'redpacket-receipt' | 'revoke';
  // 小游戏PK邀请卡片
  miniGameInvite?: {
    gameName: string;
    inviterName?: string;
  };
  // 语音通话记录：如果存在，表示这是语音通话记录消息
  voiceCallRecord?: {
    duration: number; // 通话时长（秒）
    startTime?: number; // 通话开始时间戳（毫秒）
    messages?: VoiceCallMessage[]; // 通话中的消息历史
    hangupBy?: 'self' | 'other'; // 挂断者：'self'=玩家挂断，'other'=角色挂断
    outcome?: 'connected' | 'no_answer' | 'declined'; // 结果：接通/未应答/拒接
    showRedDot?: boolean; // 是否显示右侧红点（类似未读）
  };
  // 合并转发的聊天记录
  mergedChatHistory?: {
    senderName: string; // 会话一方昵称（通常是玩家）
    receiverName: string; // 会话另一方昵称（通常是角色）
    // 可选：如果该卡片的某一侧是“已添加角色”，则记录 roleId，便于实时读取昵称/备注/头像（避免只靠字符串匹配）。
    senderRoleId?: string;
    receiverRoleId?: string;
    // 生成卡片时可选：用于详情页/卡片展示的头像信息（避免把整段 messages[] 内嵌到主会话）
    senderAvatarUrl?: string;
    senderAvatarText?: string;
    receiverAvatarUrl?: string;
    receiverAvatarText?: string;
    // 卡片的“归属时间”（用于详情页标题下的日期展示、以及让卡片看起来来自过去某个时间段）
    // - 如果存在，优先使用它作为卡片消息的 timestamp
    // - 对于“生成的聊天记录卡片”，应由模型根据上下文合理给出（如昨晚/上周/某天等）
    cardTimestamp?: number;
    // 新版：只存「来源会话 ID + 消息 ID 列表」，不再复制整段聊天内容，避免 localStorage 撑爆。
    // 详情页和预览展示时，再根据 sourceChatId + messageIds 到原会话里加载完整消息。
    sourceChatId: string; // 原始聊天所在的 chatId
    messageIds: string[]; // 被合并转发的消息 ID 列表（按时间顺序）
    // 兼容旧数据：老版本的聊天记录卡片里会直接带 messages 字段，这里保留为可选，仅在读取时使用。
    messages?: Array<{
      from?: 'other' | 'self';
      sender: string;
      senderAvatarUrl?: string;
      senderAvatarText?: string;
      text: string;
      time?: string;
      timestamp?: number;
      emojiName?: string;
      voiceDuration?: number;
    }>;
  };
  // 引用消息：如果存在，表示这条消息引用了另一条消息
  quotedMessage?: {
    id: string; // 被引用消息的ID
    from: 'other' | 'self';
    text: string; // 被引用消息的文本（可能被截断）
    senderName?: string; // 发送者名称（用于显示）
    // 群聊引用：被引用消息对应的角色ID（用于决定谁来回复 / 精确展示成员信息）
    senderRoleId?: string;
    // 如果被引用的是语音消息，可以带上语音时长用于展示
    voiceDuration?: number;
  };
  // 撤回信息（仅 systemType === 'revoke' 的系统消息使用）
  revokeMeta?: {
    // 原消息是谁发的
    originalFrom: 'self' | 'other';
    // 原消息文本（可截断保存，避免太长）
    originalText: string;
    // 原消息若为图片消息，记录其占位预览图与描述（用于撤回原文弹窗展示）
    originalImagePreviewUrl?: string;
    originalImageDesc?: string;
    // 原消息时间（可选）
    originalTime?: string;
    // 原消息 ID（可选：如果以后需要反查）
    originalMessageId?: string;
    // 谁触发撤回（玩家 / 角色）
    recalledBy: 'self' | 'other';
    // 撤回前，对方是否实际“看见过”这条内容
    seenByOther: boolean;
  };
};

// 合并转发聊天记录卡片的预览组件：
// - 每条消息单独换行显示，格式为"昵称：消息内容"
// - 每行最多显示 19 个字符（包含前面的冒号在内）
// - 最多显示 4 行内容（不是 4 条消息，可以被长消息占满）
// - 如果第 4 行还有未显示完的内容，在末尾添加省略号“…”
// - 只显示微信昵称，不显示括号加微信备注
const MergedChatPreview: React.FC<{
  history: NonNullable<ChatMessage['mergedChatHistory']>;
}> = ({ history }) => {
  // 格式化消息：每条消息为"昵称：消息内容"
  // 支持两种来源：
  // 1）旧数据：history.messages 里已经带了完整文本；
  // 2）新数据：只存了 sourceChatId + messageIds，这里按 ID 从原会话中取出完整消息。
  const formattedMessages = React.useMemo(() => {
    const list: string[] = [];
    const sourceId = String(history.sourceChatId || '');
    const senderRaw = String(history.senderName || '').trim();
    // 只有当 sourceChatId 是 chat-xxx 且 sender 看起来是玩家侧时，才认为是“玩家与某人的真实聊天记录”
    let playerNickNow = '';
    try {
      const p = loadWeChatSelfProfile();
      playerNickNow = String((p as any)?.nickname || '').trim();
    } catch {
      playerNickNow = '';
    }
    const isSenderPlayerLike =
      !senderRaw ||
      senderRaw === '我' ||
      (playerNickNow && getBaseNickname(senderRaw) === getBaseNickname(playerNickNow));
    const isRealChatSource = /^chat-/.test(sourceId) && isSenderPlayerLike;

    const resolveRoleNameWithRemark = (raw: string): string => {
      const t = String(raw || '').trim();
      if (!t) return '';
      if (t.includes('（')) return t;
      try {
        const rolesAll = loadStoryRoles();
        const contactsAll = loadWeChatContacts();
        const r = rolesAll.find(
          (rr: any) =>
            String((rr as any)?.wechatNickname || '').trim() === t || String((rr as any)?.name || '').trim() === t
        );
        if (r) {
          const c = contactsAll.find((cc: any) => cc.roleId === (r as any).id);
          const remark = String(c?.remark || '').trim();
          const baseNick = String((r as any)?.wechatNickname || (r as any)?.name || t).trim();
          return remark ? `${baseNick}（${remark}）` : baseNick;
        }
      } catch {
        // ignore
      }
      return t;
    };

    // 如果有 roleId，可直接按 roleId 读取最新昵称+备注，比纯字符串匹配更稳定
    const resolveRoleNameById = (roleId: string | undefined, fallback: string): string => {
      const safeFallback = String(fallback || '').trim() || '对方';
      const rid = String(roleId || '').trim();
      if (!rid) return safeFallback;
      try {
        const rolesAll = loadStoryRoles();
        const contactsAll = loadWeChatContacts();
        const r = rolesAll.find((rr: any) => rr.id === rid);
        const c = contactsAll.find((cc: any) => cc.roleId === rid);
        const remark = String(c?.remark || '').trim();
        const baseNick = String((r as any)?.wechatNickname || (r as any)?.name || safeFallback).trim() || safeFallback;
        return remark ? `${baseNick}（${remark}）` : baseNick;
      } catch {
        return safeFallback;
      }
    };

    // 统一的格式化函数：根据语音 / 表情等类型生成预览文本部分
    const getContentPreview = (msg: { text?: string; voiceDuration?: number; emojiName?: string }): string => {
      // 表情包：预览统一显示为「[动画表情]」，不暴露具体名称
      if (msg.emojiName) {
        return '[动画表情]';
      }
      // 语音消息：显示为「[语音]：XXXX」（如果没有文字，就用时长代替）
      if (typeof msg.voiceDuration === 'number') {
        const voiceText = (msg.text || '').trim();
        const fallback = msg.voiceDuration ? `${msg.voiceDuration}″` : '';
        return `[语音]：${voiceText || fallback}`;
      }
      // 普通文本
      return msg.text || '';
    };

    // 优先使用旧数据中的 messages（兼容历史记录）
    if (history.messages && history.messages.length > 0) {
      history.messages.forEach((m) => {
        const nickname = isRealChatSource ? getBaseNickname(m.sender) : resolveRoleNameWithRemark(m.sender);
        const content = getContentPreview(m);
        const line = `${nickname}：${content}`;
        if (line.trim().length > 0) {
          list.push(line);
        }
      });
      return list;
    }

    // 新数据：只存了引用，需要根据 sourceChatId + messageIds 重新加载原消息
    if (history.sourceChatId && history.messageIds && history.messageIds.length > 0) {
      const allMessages = loadChatMessages(history.sourceChatId);
      const map = new Map(allMessages.map((m) => [m.id, m]));

      // 为“玩家与某人的真实聊天记录”动态解析最新昵称（玩家昵称 & 角色备注）
      // 对于生成卡片 / 角色-角色记录，优先按 senderRoleId / receiverRoleId 读取最新昵称+备注
      let selfNick = isRealChatSource
        ? getBaseNickname(history.senderName)
        : resolveRoleNameById(history.senderRoleId, history.senderName || '我');
      let otherNick = isRealChatSource
        ? getBaseNickname(history.receiverName)
        : resolveRoleNameById(history.receiverRoleId, history.receiverName || '对方');
      if (isRealChatSource) {
        try {
          const m = history.sourceChatId.match(/^chat-(.+)$/);
          const roleId = m ? m[1] : null;
          if (roleId) {
            const wechatProfile = loadWeChatSelfProfile();
            selfNick = getBaseNickname((wechatProfile as any)?.nickname || '我');

            const rolesAll = loadStoryRoles();
            const contactsAll = loadWeChatContacts();
            const r = rolesAll.find((rr: any) => rr.id === roleId);
            const c = contactsAll.find((cc: any) => cc.roleId === roleId);
            const remark = String(c?.remark || '').trim();
            const baseNick = String((r as any)?.wechatNickname || (r as any)?.name || '对方').trim();
            otherNick = getBaseNickname(remark ? `${baseNick}（${remark}）` : baseNick);
          }
        } catch {
          // ignore，回退使用历史快照里的昵称
        }
      }

      history.messageIds.forEach((id) => {
        const msg = map.get(id);
        if (!msg) return;
        const from = msg.from === 'self' ? 'self' : 'other';
        const nick = from === 'self' ? selfNick : otherNick;
        const content = getContentPreview(msg);
        const line = `${nick}：${content}`;
        if (line.trim().length > 0) {
          list.push(line);
        }
      });
    }

    return list;
  }, [history]);

  // 按“每行 19 个字符、最多 4 行”的规则切分文本
  const linesToShow = React.useMemo(() => {
    const maxLines = 4;
    const maxCharsPerLine = 18;
    const result: string[] = [];

    if (formattedMessages.length === 0) return result;

    let hasMoreContent = false;

    // 逐条消息，从新行开始，按字符切分
    for (let msgIndex = 0; msgIndex < formattedMessages.length; msgIndex += 1) {
      let remaining = formattedMessages[msgIndex];

      while (remaining.length > 0) {
        if (result.length >= maxLines) {
          hasMoreContent = true;
          break;
        }

        const line = remaining.slice(0, maxCharsPerLine);
        result.push(line);
        remaining = remaining.slice(maxCharsPerLine);
      }

      if (remaining.length > 0 && result.length >= maxLines) {
        hasMoreContent = true;
      }

      if (result.length >= maxLines) {
        // 已经占满 4 行，不再处理后续消息
        if (msgIndex < formattedMessages.length - 1 || remaining.length > 0) {
          hasMoreContent = true;
        }
        break;
      }
    }

    // 如果还有未显示的内容，需要在第 4 行结尾添加省略号
    if (hasMoreContent && result.length > 0) {
      // 确保总行数不超过 4 行
      const limited = result.slice(0, maxLines);
      const lastIdx = limited.length - 1;
      let lastLine = limited[lastIdx];

      // 预留 1 个字符给省略号
      if (lastLine.length >= maxCharsPerLine) {
        lastLine = lastLine.slice(0, maxCharsPerLine - 1);
      }
      limited[lastIdx] = `${lastLine}…`;
      return limited;
    }

    return result.slice(0, maxLines);
  }, [formattedMessages]);

  return (
    <div
      style={{
        padding: '8px 12px',
        fontSize: '13px',
        color: '#6b7280',
        lineHeight: '20px',
        wordBreak: 'break-word',
        whiteSpace: 'pre-wrap',
        minHeight: '32px'
      }}
    >
      {linesToShow.map((line, idx) => (
        // eslint-disable-next-line react/no-array-index-key
        <div key={idx}>
          {line}
        </div>
      ))}
    </div>
  );
};

// 聊天长期记忆快照（按会话/角色本地存储）
type ChatMemorySnapshot = {
  id: string;
  chatId: string;
  roleId?: string;
  roleName?: string;
  title: string;
  summary: string;
  createdAt: string;
  updatedAt: string;
};

// 聊天记忆相关全局配置
type WeChatMemorySettings = {
  autoSummaryEnabled: boolean;
  // 每多少轮角色回复后自动总结一次（按每次 AI 回复算一轮）
  summaryInterval: number;
};

// 共同好友聊天模式设置
type WeChatMutualFriendChatSettings = {
  enabled: boolean; // 是否启用共同好友聊天模式
};

// 线上 / 线下联动模式设置
type WeChatStoryLinkSettings = {
  // 是否在收到玩家微信消息后**额外自动**生成一段线下剧情（Story）；与「提示词是否读线下」无关
  enabled: boolean;
};

// 主动语音来电：合并进「单次主回复」解析，不再单独请求模型判断
type WeChatAutoVoiceCallSettings = {
  enabled: boolean;
};

// 主回复末尾 <<MUTUAL_FRIEND_CHAIN>> JSON（仅共同好友模式开启时注入提示词）
type MutualFriendChainPayload = {
  relayTo?: Array<{ otherRoleId?: string; relayedMessage?: string }>;
  otherOutgoing?: Array<{ otherRoleId?: string; lines?: string[] }>;
};

// 弹幕模式风格预设
type WeChatDanmakuStylePreset = 'balanced' | 'warm' | 'lively' | 'crazy' | 'cool';

// 微信全局弹幕模式配置
type WeChatDanmakuSettings = {
  // 是否全局启用弹幕模式（仍然受每个会话的单独开关控制）
  enabled: boolean;
  // 当前选中的风格预设；为 'custom' 时使用 customStyleText
  stylePreset: WeChatDanmakuStylePreset | 'custom';
  // 自定义弹幕风格描述（写给模型看的语气提示）
  customStyleText: string;
  // 每轮希望生成的大致弹幕条数（最终由模型决定，范围约 1～20）
  perRoundCount: number;
  // 弹幕生成所用的 API：default=沿用全局聊天 API；custom=使用专属弹幕 API
  apiMode: 'default' | 'custom';
  customApiBaseUrl?: string;
  customApiKey?: string;
  customApiModel?: string;
  // 弹幕在聊天窗口中垂直方向的可用高度占比（0.25～1，对应 25%～100%）
  viewportHeightRatio: number;
};

