const openChatMessagesDb = (): Promise<IDBDatabase> => openAppDb();

const idbGetChatMessages = async (chatId: string): Promise<ChatMessage[] | null> => {
  const db = await openChatMessagesDb();
  return await new Promise((resolve) => {
    try {
      const tx = db.transaction(CHAT_MESSAGES_STORE, 'readonly');
      const store = tx.objectStore(CHAT_MESSAGES_STORE);
      const req = store.get(chatId);
      req.onsuccess = () => {
        const v = req.result as any;
        resolve(Array.isArray(v) ? (v as ChatMessage[]) : null);
      };
      req.onerror = () => resolve(null);
    } catch {
      resolve(null);
    }
  });
};

const idbPutChatMessages = async (chatId: string, messages: ChatMessage[]): Promise<void> => {
  const db = await openChatMessagesDb();
  await new Promise<void>((resolve) => {
    try {
      const tx = db.transaction(CHAT_MESSAGES_STORE, 'readwrite');
      const store = tx.objectStore(CHAT_MESSAGES_STORE);
      store.put(messages, chatId);
      tx.oncomplete = () => resolve();
      tx.onerror = () => resolve();
      tx.onabort = () => resolve();
    } catch {
      resolve();
    }
  });
};

// 删除 IndexedDB 中的聊天消息
const idbDeleteChatMessages = async (chatId: string): Promise<void> => {
  const db = await openChatMessagesDb();
  await new Promise<void>((resolve) => {
    try {
      const tx = db.transaction(CHAT_MESSAGES_STORE, 'readwrite');
      const store = tx.objectStore(CHAT_MESSAGES_STORE);
      store.delete(chatId);
      tx.oncomplete = () => resolve();
      tx.onerror = () => resolve();
      tx.onabort = () => resolve();
    } catch {
      resolve();
    }
  });
};

const upgradeChatMessages = (parsed: any): ChatMessage[] => {
  if (!Array.isArray(parsed)) return [];

  // 兼容历史数据：过去的表情消息可能只有 "[表情] 名称" 的文本，没有 emojiName 字段
  const upgraded = (parsed as ChatMessage[]).map((msg) => {
    if (!msg || typeof (msg as any).text !== 'string') return msg as any;
    if ((msg as any).emojiName) return msg as any;

    const text = String((msg as any).text || '');
    const match =
      text.match(/^[\[【]表情[\]】]\s*(.+)$/u) ||
      text.match(/^[\[【]表情[\]】]\s*([^，,。.!！?？\s]+(?:[（(][^）)]*[）)])?)/u);

    if (!match) return msg as any;

    let emojiName = match[1].trim();
    const candidates: string[] = [emojiName];
    const strippedOnce = emojiName.replace(/（[^）]*）$/u, '').trim();
    if (strippedOnce && strippedOnce !== emojiName) {
      candidates.push(strippedOnce);
    }

    let emojiConfig = undefined as ReturnType<typeof findEmojiByName> | undefined;
    for (const candidate of candidates) {
      emojiConfig = findEmojiByName(candidate);
      if (emojiConfig) {
        emojiName = emojiConfig.name;
        break;
      }
    }

    if (!emojiConfig) return msg as any;

    return {
      ...(msg as any),
      text: `[表情] ${emojiName}`,
      emojiName
    } as any;
  });

  return upgraded;
};
