// 计算微信相关数据在 appStorage 中的大致占用（按类别聚合，用于「查看存储空间」页面）
const calculateWeChatStorageUsage = (): StorageUsageSummary => {
  const keys = appStorage.keys();
  const categories: Record<
    'chatMessages' | 'chatMemories' | 'wechatConfig' | 'storyData' | 'other',
    number
  > = {
    chatMessages: 0,
    chatMemories: 0,
    wechatConfig: 0,
    storyData: 0,
    other: 0
  };

  for (const key of keys) {
    const value = appStorage.getItem(key);
    const size = typeof value === 'string' ? value.length : 0;

    if (!key.startsWith('mini-ai-phone.')) {
      // 非本应用的数据，忽略
      continue;
    }

    if (key.startsWith(CHAT_MESSAGES_KEY_PREFIX)) {
      categories.chatMessages += size;
    } else if (
      key.startsWith(CHAT_MEMORY_KEY_PREFIX) ||
      key.startsWith(CHAT_MEMORY_COUNTER_PREFIX) ||
      key.startsWith(STORY_MEMORY_KEY_PREFIX) ||
      key.startsWith(STORY_MEMORY_COUNTER_PREFIX)
    ) {
      categories.chatMemories += size;
    } else if (key.startsWith('mini-ai-phone.wechat-')) {
      categories.wechatConfig += size;
    } else if (key.startsWith('mini-ai-phone.story-')) {
      categories.storyData += size;
    } else {
      categories.other += size;
    }
  }

  const palette = ['#0ea5e9', '#22c55e', '#f97316', '#a855f7', '#9ca3af'];
  const entries: StorageUsageCategory[] = [
    { key: 'chatMessages', label: '聊天记录', bytes: categories.chatMessages, color: palette[0] },
    { key: 'chatMemories', label: '对话记忆', bytes: categories.chatMemories, color: palette[1] },
    { key: 'wechatConfig', label: '微信设置与偏好', bytes: categories.wechatConfig, color: palette[2] },
    { key: 'storyData', label: '角色与剧情数据', bytes: categories.storyData, color: palette[3] },
    { key: 'other', label: '其它', bytes: categories.other, color: palette[4] }
  ].filter((item) => item.bytes > 0);

  const totalBytes = entries.reduce((sum, item) => sum + item.bytes, 0);

  return {
    totalBytes,
    categories: entries
  };
};

// 将字节数格式化为更易读的字符串
const formatBytes = (bytes: number): string => {
  if (!bytes || bytes <= 0) return '0 KB';
  const kb = bytes / 1024;
  if (kb < 1024) return `${kb.toFixed(1)} KB`;
  const mb = kb / 1024;
  if (mb < 1024) return `${mb.toFixed(1)} MB`;
  const gb = mb / 1024;
  return `${gb.toFixed(2)} GB`;
};

