type PhoneInspectWechatGeneratedChat = {
  id: string;
  name: string;
  avatarText: string;
  avatarUrl?: string;
  time: string;
  lastMessage: string;
  unread: number;
  messages: PhoneInspectWechatGeneratedChatMessage[];
};

type PhoneInspectWechatGeneratedContact = {
  id: string;
  name: string;
  avatarText: string;
  avatarUrl?: string;
  boundRoleId?: string;
  source: 'bound-npc' | 'unbound-new';
};

type PhoneInspectWechatGeneratedWalletBill = {
  id: string;
  title: string;
  amount: number;
  time: string;
};

type PhoneInspectWechatGeneratedData = {
  roleId: string;
  chats: PhoneInspectWechatGeneratedChat[];
  contacts: PhoneInspectWechatGeneratedContact[];
  wallet: {
    walletId: string;
    balance: number;
    paymentPassword: string;
    bills: PhoneInspectWechatGeneratedWalletBill[];
  };
};

const PHONE_INSPECT_WECHAT_CACHE_KEY = 'mini-ai-phone.inspect-wechat-generated-v1';

const loadInspectWechatGeneratedCache = (): Record<string, PhoneInspectWechatGeneratedData> => {
  try {
    const raw = appStorage.getItem(PHONE_INSPECT_WECHAT_CACHE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {};
    return parsed as Record<string, PhoneInspectWechatGeneratedData>;
  } catch {
    return {};
  }
};

const saveInspectWechatGeneratedForRole = (ownerRoleId: string, data: PhoneInspectWechatGeneratedData) => {
  if (!ownerRoleId || !data?.chats?.length || !data?.contacts?.length) return;
  try {
    const all = loadInspectWechatGeneratedCache();
    all[ownerRoleId] = data;
    appStorage.setItem(PHONE_INSPECT_WECHAT_CACHE_KEY, JSON.stringify(all));
  } catch {
    // ignore
  }
};

/** 查手机微信：读取本地缓存（与 save 成功写入条件一致，保证结构完整） */
const loadCachedInspectWechatForRole = (roleId: string): PhoneInspectWechatGeneratedData | null => {
  if (!roleId) return null;
  const all = loadInspectWechatGeneratedCache();
  const d = all[roleId];
  if (!d || !Array.isArray(d.chats) || !Array.isArray(d.contacts) || !d.wallet) return null;
  if (!d.chats.length || !d.contacts.length) return null;
  // 防止存储键与内容 roleId 不一致时误展示
  if (String(d.roleId || '').trim() !== String(roleId).trim()) return null;
  return d;
};

/** 主角色人脉：优先读 relations（编辑页保存），并兼容旧字段 relationsToOthers（须含 otherRoleId） */
const getInspectBoundRelations = (role: StoryRole): RoleRelationship[] => {
  const seen = new Set<string>();
  const out: RoleRelationship[] = [];
  const primary = Array.isArray(role.relations) ? role.relations : [];
  for (const rel of primary) {
    const oid = String(rel?.otherRoleId || '').trim();
    if (!oid || oid === role.id) continue;
    if (seen.has(oid)) continue;
    seen.add(oid);
    out.push(rel);
  }
  const legacy = Array.isArray((role as any).relationsToOthers) ? ((role as any).relationsToOthers as any[]) : [];
  for (const x of legacy) {
    const oid = String(x?.otherRoleId || '').trim();
    if (!oid || oid === role.id || seen.has(oid)) continue;
    seen.add(oid);
    const relType = (String(x?.relation || '').trim() as RoleRelationType) || 'friend';
    const safeRelation: RoleRelationType = [
      'stranger',
      'friend',
      'family',
      'colleague',
      'lover',
      'ex',
      'schoolmate',
      'roommate',
      'boss_subordinate',
      'other'
    ].includes(relType)
      ? relType
      : 'friend';
    out.push({
      otherRoleId: oid,
      relation: safeRelation,
      note: String(x?.note || '').trim() || undefined,
      customLabel: String(x?.graphLabel || x?.customLabel || '').trim() || undefined
    });
  }
  return out;
};

/** 稳定哈希：用于无绑定联系人头像下标，避免多人共用同一张默认图 */
const hashStringInspect = (s: string): number => {
  let h = 0;
  const str = String(s || '');
  for (let i = 0; i < str.length; i++) {
    h = (Math.imul(31, h) + str.charCodeAt(i)) | 0;
  }
  return h;
};

const pickAvatarForInspectStoryRole = (r: StoryRole, used: Set<string>): string => {
  const existing = String(r.avatarUrl || '').trim();
  if (existing) {
    used.add(existing);
    return existing;
  }
  const gender = r.gender || '';
  const textBlob = `${r.name || ''}${r.intro || ''}${r.quote || ''}`;
  const isElderByAge = typeof r.age === 'number' && Number.isFinite(r.age) && r.age >= 45;
  const elderKeywords = ['爸', '妈', '叔', '伯', '舅', '姨', '阿姨', '大爷', '奶奶', '外公', '外婆', '长辈', '老师', '导师'];
  const isElderByText = elderKeywords.some((k) => textBlob.includes(k));
  const isElder = isElderByAge || isElderByText;
  let pool: string[] = [];
  if (isElder) {
    if (gender === 'female') pool = ELDER_FEMALE_AVATARS;
    else if (gender === 'male') pool = ELDER_MALE_AVATARS;
    else pool = [...ELDER_MALE_AVATARS, ...ELDER_FEMALE_AVATARS];
  } else {
    if (gender === 'female') pool = DEFAULT_FEMALE_AVATARS;
    else if (gender === 'male') pool = DEFAULT_MALE_AVATARS;
    else pool = [...DEFAULT_MALE_AVATARS, ...DEFAULT_FEMALE_AVATARS];
  }
  if (!pool.length) return '';
  const h = hashStringInspect(String(r.id || r.name || ''));
  for (let offset = 0; offset < pool.length; offset++) {
    const cand = pool[(Math.abs(h) + offset) % pool.length];
    if (!used.has(cand)) {
      used.add(cand);
      return cand;
    }
  }
  const mega = [...new Set([...DEFAULT_MALE_AVATARS, ...DEFAULT_FEMALE_AVATARS, ...ELDER_MALE_AVATARS, ...ELDER_FEMALE_AVATARS])];
  for (let offset = 0; offset < mega.length; offset++) {
    const cand = mega[(Math.abs(h) + offset) % mega.length];
    if (!used.has(cand)) {
      used.add(cand);
      return cand;
    }
  }
  const fallback = pool[Math.abs(h) % pool.length];
  used.add(fallback);
  return fallback;
};

/** 无 boundRoleId 的联系人：按显示名猜年龄/性别，从默认头像库选图；salt 用于同一显示名去重 */
const pickAvatarForInspectUnboundName = (displayName: string, used: Set<string>, salt = ''): string => {
  const raw = String(displayName || '').trim();
  const blob = `${raw}\0${salt}`;
  // 亲属称呼：单独加强，避免「妈妈」因 总/爷 等字计数误判成男
  const motherStrong =
    /^(妈妈|妈咪|老妈|咱妈|我妈|娘|娘亲|母上|太后|母亲)([（(].*[)）])?$/u.test(raw) ||
    /(妈妈|妈咪|老妈|咱妈|我妈|娘亲|母上|太后)(?![^（(]*[)）])/u.test(raw);
  const fatherStrong =
    /^(爸爸|老爸|爹|咱爸|我爸|父亲|老爷子)([（(].*[)）])?$/u.test(raw) ||
    /(爸爸|老爸|爹|父亲)(?![^（(]*[)）])/u.test(raw);
  const elderKeywords = ['爸', '妈', '叔', '伯', '舅', '姨', '阿姨', '大妈', '大爷', '奶奶', '爷', '外公', '外婆', '导师', '老师'];
  const isElder = elderKeywords.some((k) => raw.includes(k));
  let gender: 'male' | 'female' | '' = '';
  if (motherStrong) gender = 'female';
  else if (fatherStrong) gender = 'male';
  const femaleHints = ['姐', '姨', '妈', '奶', '婆', '小姐', '姑娘', '女'];
  const maleHints = ['哥', '弟', '叔', '伯', '爷', '先生', '总'];
  const fCount = femaleHints.filter((h) => raw.includes(h)).length;
  const mCount = maleHints.filter((h) => raw.includes(h)).length;
  if (!gender) {
    if (fCount > mCount) gender = 'female';
    else if (mCount > fCount) gender = 'male';
  }
  let pool: string[] = [];
  if (isElder) {
    if (gender === 'female') pool = ELDER_FEMALE_AVATARS;
    else if (gender === 'male') pool = ELDER_MALE_AVATARS;
    else pool = [...ELDER_MALE_AVATARS, ...ELDER_FEMALE_AVATARS];
  } else {
    if (gender === 'female') pool = DEFAULT_FEMALE_AVATARS;
    else if (gender === 'male') pool = DEFAULT_MALE_AVATARS;
    else pool = [...DEFAULT_MALE_AVATARS, ...DEFAULT_FEMALE_AVATARS];
  }
  if (!pool.length) return '';
  const h = hashStringInspect(blob);
  for (let offset = 0; offset < pool.length; offset++) {
    const cand = pool[(Math.abs(h) + offset) % pool.length];
    if (!used.has(cand)) {
      used.add(cand);
      return cand;
    }
  }
  const mega = [...new Set([...DEFAULT_MALE_AVATARS, ...DEFAULT_FEMALE_AVATARS, ...ELDER_MALE_AVATARS, ...ELDER_FEMALE_AVATARS])];
  for (let offset = 0; offset < mega.length + 32; offset++) {
    const cand = mega[(Math.abs(h) + offset) % mega.length];
    if (!used.has(cand)) {
      used.add(cand);
      return cand;
    }
  }
  const fallback = pool[Math.abs(h) % pool.length];
  used.add(fallback);
  return fallback;
};

/** 玩家在微信资料 + 与该角色绑定的身份马甲（用于匹配通讯录/会话里的「对方」是否为玩家） */
const collectPlayerInspectAliases = (owner: StoryRole | null | undefined): string[] => {
  const sp = loadWeChatSelfProfile();
  const set = new Set<string>();
  const nick = String(sp.nickname || '').trim();
  if (nick && nick !== '微信昵称') set.add(nick);
  if (owner) {
    const w = String(owner.playerIdentityWechatNickname || '').trim();
    if (w) set.add(w);
    const nm = String(owner.playerIdentityName || '').trim();
    if (nm) set.add(nm);
    const call = String(owner.playerCallMe || '').trim();
    if (call) set.add(call);
  }
  return Array.from(set).filter(Boolean);
};

/** 查手机通讯录里「玩家」条目的推荐显示名：仅人设备注/称呼，不在括号里再拼玩家微信昵称 */
const buildSuggestedPlayerInspectContactName = (owner: StoryRole): string => {
  const sp = loadWeChatSelfProfile();
  const nickRaw = String(sp.nickname || '').trim();
  const nick = nickRaw && nickRaw !== '微信昵称' ? nickRaw : '';
  const identityNick = String(owner.playerIdentityWechatNickname || '').trim();
  const identityName = String(owner.playerIdentityName || '').trim();
  const callMe = String(owner.playerCallMe || '').trim();
  if (callMe) return callMe;
  // 关键：查手机里“玩家联系人显示名”必须优先使用玩家身份卡真实姓名/身份名，而不是微信昵称。
  return identityName || identityNick || nick || '你';
};

const expandPlayerInspectAliases = (owner: StoryRole | null | undefined): string[] => {
  const base = collectPlayerInspectAliases(owner);
  const set = new Set(base);
  if (owner) {
    const suggested = buildSuggestedPlayerInspectContactName(owner);
    if (suggested) {
      set.add(suggested);
      const inner = suggested.match(/（([^）]+)）\s*$/u);
      if (inner?.[1]) set.add(inner[1].trim());
      const outer = suggested.replace(/（[^）]+）\s*$/u, '').trim();
      if (outer) set.add(outer);
    }
  }
  return Array.from(set).filter(Boolean);
};

const normKeyInspectContact = (raw: string): string => {
  const t = String(raw || '').trim().replace(/\s+/g, '');
  if (!t) return '';
  const base = t.replace(/（[^）]+）\s*$/u, '').trim();
  return (base || t).toLowerCase();
};

const contactDisplayMatchesPlayer = (rawName: string, aliases: string[]): boolean => {
  const n = String(rawName || '').trim().toLowerCase();
  if (!n) return false;
  for (const a of aliases) {
    const t = String(a || '').trim().toLowerCase();
    if (!t || t === '微信昵称') continue;
    if (n === t) return true;
    // 收紧匹配：短昵称/单字（如“嗯”）不做包含匹配，避免把无意义昵称误识别为玩家本人
    const aLen = Array.from(t).length;
    const nLen = Array.from(n).length;
    if (aLen <= 2 || nLen <= 2) continue;
    if (n.includes(t)) return true;
    if (t.includes(n)) return true;
  }
  return false;
};

/** AI 常用无意义单字当玩家：需识别并合并为同一条「玩家」联系人 */
const GENERIC_INSPECT_PLAYER_NAMES = new Set([
  '嗯',
  '哦',
  '呃',
  '额',
  '哈',
  '诶',
  '欸',
  '你',
  '我',
  'ta',
  'TA',
  '…',
  '...',
  '微信用户',
  '用户',
  '昵称',
  '网名'
]);

const looksLikeGenericInspectPlayerPlaceholder = (raw: string): boolean => {
  const n = String(raw || '').trim();
  return GENERIC_INSPECT_PLAYER_NAMES.has(n);
};

const inspectContactIsPlayerRow = (rawName: string, aliases: string[]): boolean =>
  contactDisplayMatchesPlayer(rawName, aliases) || looksLikeGenericInspectPlayerPlaceholder(rawName);

/** AI 未写 boundRoleId 时，用显示名反查故事角色（优先人脉中的 otherRoleId） */
const inferStoryRoleIdFromInspectContactName = (
  rawName: string,
  owner: StoryRole,
  allRoles: StoryRole[],
  playerAliases: string[]
): string | undefined => {
  if (inspectContactIsPlayerRow(rawName, playerAliases)) return undefined;
  const name = String(rawName || '').trim();
  if (!name) return undefined;
  const base = name.replace(/（[^）]+）\s*$/u, '').trim();
  const rels = getInspectBoundRelations(owner);
  const relIdList = rels.map((r) => r.otherRoleId).filter(Boolean);
  const tryIds: string[] = [];
  const seen = new Set<string>();
  for (const id of relIdList) {
    if (!seen.has(id)) {
      seen.add(id);
      tryIds.push(id);
    }
  }
  for (const r of allRoles) {
    if (r.id === owner.id) continue;
    if (!seen.has(r.id)) {
      seen.add(r.id);
      tryIds.push(r.id);
    }
  }

  const nameMatchesRole = (oid: string): boolean => {
    const o = allRoles.find((x) => x.id === oid);
    if (!o) return false;
    const nick = String(o.wechatNickname || '').trim();
    const rname = String(o.name || '').trim();
    const labels = rels.filter((x) => x.otherRoleId === oid).map((x) => String(x.customLabel || '').trim()).filter(Boolean);
    // 只收录「该角色侧」可能出现的显示名，禁止把待匹配的 name 塞进 variants，否则 variants.has(name) 会对第一个 tryIds 恒为真
    const variants = new Set<string>();
    [nick, rname].forEach((piece) => {
      if (!piece) return;
      variants.add(piece);
      labels.forEach((lab) => variants.add(`${piece}（${lab}）`));
    });
    labels.forEach((lab) => {
      if (lab) variants.add(lab);
    });
    if (variants.has(name)) return true;
    if (base && base !== name && variants.has(base)) return true;
    if (base && (base === nick || base === rname)) return true;
    return false;
  };

  for (const oid of tryIds) {
    if (nameMatchesRole(oid)) return oid;
  }
  // 不再做「显示名包含对方昵称」的模糊匹配：极易把「妈妈」等备注误绑到无关 NPC，造成通讯录缺行、头像串号
  return undefined;
};

/** 修正 AI 漏写/错写的 boundRoleId，并把误标为 NPC 的「玩家」条目还原 */
const repairInspectWechatContactBindings = (
  owner: StoryRole,
  allRoles: StoryRole[],
  contacts: PhoneInspectWechatGeneratedContact[]
): PhoneInspectWechatGeneratedContact[] => {
  const aliases = expandPlayerInspectAliases(owner);
  return contacts.map((c) => {
    const display = String(c.name || '').trim();
    if (inspectContactIsPlayerRow(display, aliases)) {
      return { ...c, boundRoleId: undefined, source: 'unbound-new' as const };
    }
    const bid = String(c.boundRoleId || '').trim();
    const roleExists = bid && allRoles.some((r) => r.id === bid);
    if (roleExists) return c;
    const inferred = inferStoryRoleIdFromInspectContactName(display, owner, allRoles, aliases);
    if (inferred) {
      return { ...c, boundRoleId: inferred, source: 'bound-npc' as const };
    }
    return { ...c, boundRoleId: undefined };
  });
};

/** 合并重复联系人/会话；玩家多条合并为一条并统一为人设备注名 */
const dedupeInspectWechatContactsAndChats = (
  owner: StoryRole,
  contacts: PhoneInspectWechatGeneratedContact[],
  chats: PhoneInspectWechatGeneratedChat[]
): { contacts: PhoneInspectWechatGeneratedContact[]; chats: PhoneInspectWechatGeneratedChat[] } => {
  const aliases = expandPlayerInspectAliases(owner);
  const playerOnes = contacts.filter((c) => inspectContactIsPlayerRow(String(c.name || ''), aliases));
  const nonPlayer = contacts.filter((c) => !inspectContactIsPlayerRow(String(c.name || ''), aliases));

  const byBound = new Map<string, PhoneInspectWechatGeneratedContact>();
  for (const c of nonPlayer) {
    const bid = String(c.boundRoleId || '').trim();
    if (!bid) continue;
    const prev = byBound.get(bid);
    if (!prev || String(c.name || '').length > String(prev.name || '').length) {
      byBound.set(bid, c);
    }
  }

  const byNormUnbound = new Map<string, PhoneInspectWechatGeneratedContact>();
  for (const c of nonPlayer) {
    if (c.boundRoleId) continue;
    const key = normKeyInspectContact(String(c.name || ''));
    if (!key) continue;
    const prev = byNormUnbound.get(key);
    if (!prev || String(c.name || '').length > String(prev.name || '').length) {
      byNormUnbound.set(key, c);
    }
  }

  const suggestedPlayerName = buildSuggestedPlayerInspectContactName(owner);
  const outContacts: PhoneInspectWechatGeneratedContact[] = [];

  if (playerOnes.length) {
    outContacts.push({
      ...playerOnes[0],
      name: suggestedPlayerName,
      boundRoleId: undefined,
      source: 'unbound-new',
      id: String(playerOnes[0].id || 'inspect-player-unified')
    });
  }

  const emittedBound = new Set<string>();
  const emittedNorm = new Set<string>();

  for (const c of contacts) {
    if (inspectContactIsPlayerRow(String(c.name || ''), aliases)) continue;
    const bid = String(c.boundRoleId || '').trim();
    if (bid) {
      if (emittedBound.has(bid)) continue;
      const row = byBound.get(bid);
      if (row) {
        outContacts.push(row);
        emittedBound.add(bid);
      }
      continue;
    }
    const nk = normKeyInspectContact(String(c.name || ''));
    if (!nk) continue;
    if (emittedNorm.has(nk)) continue;
    const row = byNormUnbound.get(nk);
    if (row) {
      outContacts.push(row);
      emittedNorm.add(nk);
    }
  }

  // 二次兜底：无论模型把玩家写成什么昵称，只要被识别为玩家行，一律改成“身份卡真实姓名/称呼”。
  for (let i = 0; i < outContacts.length; i += 1) {
    const c = outContacts[i];
    if (inspectContactIsPlayerRow(String(c.name || ''), aliases)) {
      outContacts[i] = {
        ...c,
        name: suggestedPlayerName,
        boundRoleId: undefined,
        source: 'unbound-new'
      };
    }
  }

  const normToCanon = new Map<string, string>();
  outContacts.forEach((c) => {
    const nk = normKeyInspectContact(String(c.name || ''));
    if (nk) normToCanon.set(nk, String(c.name || '').trim());
  });

  const anyPlayer = playerOnes.length > 0;
  const playerChatNormKey = '__inspect_player_chat__';
  const chatByNorm = new Map<string, PhoneInspectWechatGeneratedChat>();
  for (const ch of chats) {
    const rawNm = String(ch.name || '').trim();
    const nk =
      anyPlayer && inspectContactIsPlayerRow(rawNm, aliases)
        ? playerChatNormKey
        : normKeyInspectContact(rawNm) || `__${rawNm.toLowerCase()}`;
    const prev = chatByNorm.get(nk);
    const pm = (ch.messages || []).length;
    const qm = (prev?.messages || []).length;
    if (!prev || pm > qm) chatByNorm.set(nk, ch);
  }

  const emittedChatNorm = new Set<string>();
  const outChats: PhoneInspectWechatGeneratedChat[] = [];
  for (const ch of chats) {
    const rawNm = String(ch.name || '').trim();
    const nk =
      anyPlayer && inspectContactIsPlayerRow(rawNm, aliases)
        ? playerChatNormKey
        : normKeyInspectContact(rawNm) || `__${rawNm.toLowerCase()}`;
    if (emittedChatNorm.has(nk)) continue;
    const best = chatByNorm.get(nk);
    if (!best) continue;
    const canon =
      nk === playerChatNormKey && anyPlayer
        ? suggestedPlayerName
        : normToCanon.get(normKeyInspectContact(rawNm)) || normToCanon.get(nk) || rawNm;
    outChats.push({
      ...best,
      name: canon
    });
    emittedChatNorm.add(nk);
  }

  return { contacts: outContacts, chats: outChats };
};

/** 微信主页会话列表里的对象，若通讯录缺条目则补一条，避免「有会话无联系人」 */
const ensureInspectContactsCoverChats = (
  owner: StoryRole,
  allRoles: StoryRole[],
  contacts: PhoneInspectWechatGeneratedContact[],
  chats: PhoneInspectWechatGeneratedChat[]
): PhoneInspectWechatGeneratedContact[] => {
  const aliases = expandPlayerInspectAliases(owner);
  const list = [...contacts];
  const seen = new Set(list.map((c) => normKeyInspectContact(String(c.name || ''))).filter(Boolean));
  const seenBound = new Set(list.map((c) => String(c.boundRoleId || '').trim()).filter(Boolean));

  for (const ch of chats) {
    const nm = String(ch.name || '').trim();
    if (!nm) continue;
    const nk = normKeyInspectContact(nm) || `__${nm.toLowerCase()}`;
    if (inspectContactIsPlayerRow(nm, aliases)) {
      const hasPlayer = list.some((c) => inspectContactIsPlayerRow(String(c.name || ''), aliases));
      if (hasPlayer) continue;
    }
    if (seen.has(nk)) continue;
    let inferred = inferStoryRoleIdFromInspectContactName(nm, owner, allRoles, aliases);
    // 已存在同 boundRoleId 的联系人：仅当通讯录显示名与会话标题一致时才视为同一条；否则补一条 unbound，避免「有会话无联系人」或头像跟错人
    if (inferred && seenBound.has(inferred)) {
      const holder = list.find((c) => String(c.boundRoleId || '').trim() === inferred);
      const holderNk = holder ? normKeyInspectContact(String(holder.name || '')) : '';
      if (holder && holderNk === nk) {
        seen.add(nk);
        continue;
      }
      inferred = undefined;
    }
    const ct: PhoneInspectWechatGeneratedContact = {
      id: `inspect-from-chat-${String(ch.id || nk).replace(/\s+/g, '-')}`,
      name: nm,
      avatarText: nm.charAt(0) || '联',
      avatarUrl: '',
      boundRoleId: inferred,
      source: inferred ? 'bound-npc' : 'unbound-new'
    };
    if (inferred) seenBound.add(inferred);
    list.push(ct);
    seen.add(nk);
  }
  return list;
};

/** 补全人脉里已绑定故事角色但 AI 未写入的通讯录与会话（会话可先空，刷新后由 AI 填） */
const mergeInspectWechatMissingRelationContacts = (
  owner: StoryRole,
  allRoles: StoryRole[],
  data: PhoneInspectWechatGeneratedData
): PhoneInspectWechatGeneratedData => {
  const rels = getInspectBoundRelations(owner);
  if (!rels.length) return data;
  const contacts = [...data.contacts];
  const chats = [...data.chats];
  const boundIds = new Set(contacts.filter((c) => c.boundRoleId).map((c) => String(c.boundRoleId)));
  const usedAv = new Set<string>();

  for (const rel of rels) {
    const oid = String(rel.otherRoleId || '').trim();
    if (!oid || boundIds.has(oid)) continue;
    const o = allRoles.find((x) => x.id === oid);
    if (!o) continue;
    const baseNick = String(o.wechatNickname || o.name || '联系人').trim();
    // 人脉 customLabel 仅作生成参考，不在此拼成「昵称（标签）」；占位行用对方昵称即可
    const displayName = baseNick;
    const av = pickAvatarForInspectStoryRole(o, usedAv);
    const ct: PhoneInspectWechatGeneratedContact = {
      id: `inspect-rel-${oid}`,
      name: displayName,
      avatarText: displayName.charAt(0) || '联',
      avatarUrl: av,
      boundRoleId: oid,
      source: 'bound-npc'
    };
    contacts.unshift(ct);
    boundIds.add(oid);
    if (!chats.some((ch) => String(ch.name || '').trim() === displayName)) {
      chats.unshift({
        id: `inspect-chat-rel-${oid}`,
        name: displayName,
        avatarText: ct.avatarText,
        avatarUrl: av,
        time: '',
        lastMessage: '',
        unread: 0,
        messages: []
      });
    }
  }
  return { ...data, contacts, chats };
};

/**
 * 去掉历史/模型生成的「微信昵称+（人脉 graphLabel）」后缀；人脉标签仅供参考，不应以括号形式拼在昵称后。
 * 若备注应单独显示，由模型在 name 里直接输出纯备注（见生成提示），此处不做「昵称→备注」拼接。
 */
const stripInspectRelationParenSuffixFromInspectData = (
  owner: StoryRole,
  allRoles: StoryRole[],
  playerAliases: string[],
  contacts: PhoneInspectWechatGeneratedContact[],
  chats: PhoneInspectWechatGeneratedChat[]
): { contacts: PhoneInspectWechatGeneratedContact[]; chats: PhoneInspectWechatGeneratedChat[] } => {
  const rels = getInspectBoundRelations(owner);
  const labelByRole = new Map<string, string>();
  for (const rel of rels) {
    const oid = String(rel?.otherRoleId || '').trim();
    const lab = String(rel?.customLabel || '').trim();
    if (!oid || !lab || labelByRole.has(oid)) continue;
    labelByRole.set(oid, lab);
  }
  if (!labelByRole.size) return { contacts, chats };

  const stripIfEndsWithGraphLabel = (raw: string, boundId: string): string => {
    const t = String(raw || '').trim();
    if (!t) return t;
    const lab = labelByRole.get(String(boundId || '').trim());
    if (!lab) return t;
    const suffix = `（${lab}）`;
    if (!t.endsWith(suffix)) return t;
    const next = t.slice(0, t.length - suffix.length).trim();
    return next || t;
  };

  const nextContacts = contacts.map((c) => {
    const bid = String(c.boundRoleId || '').trim();
    if (!bid) return c;
    const nm = String(c.name || '').trim();
    const nextName = stripIfEndsWithGraphLabel(nm, bid);
    return nextName !== nm ? { ...c, name: nextName } : c;
  });

  const nextChats = chats.map((ch) => {
    const nm = String(ch.name || '').trim();
    if (!nm) return ch;
    const inferred = inferStoryRoleIdFromInspectContactName(nm, owner, allRoles, playerAliases);
    if (!inferred) return ch;
    const nextName = stripIfEndsWithGraphLabel(nm, inferred);
    return nextName !== nm ? { ...ch, name: nextName } : ch;
  });

  return { contacts: nextContacts, chats: nextChats };
};

const applyInspectWechatResolvedAvatars = (
  data: PhoneInspectWechatGeneratedData,
  allRoles: StoryRole[],
  owner: StoryRole,
  playerAliases: string[],
  playerAvatarUrl: string
): PhoneInspectWechatGeneratedData => {
  const used = new Set<string>();
  const roleById = new Map(allRoles.map((r) => [r.id, r]));
  const pAv = String(playerAvatarUrl || '').trim();
  const canonPlayer = buildSuggestedPlayerInspectContactName(owner);

  const contacts = data.contacts.map((c, idx) => {
    let url = String(c.avatarUrl || '').trim();
    const display = String(c.name || '').trim();
    if (pAv && (inspectContactIsPlayerRow(display, playerAliases) || display === canonPlayer)) {
      url = pAv;
      used.add(pAv);
    } else if (c.boundRoleId) {
      const r = roleById.get(c.boundRoleId);
      if (r) {
        const ru = String(r.avatarUrl || '').trim();
        if (ru) {
          if (used.has(ru)) {
            url = pickAvatarForInspectStoryRole({ ...r, avatarUrl: '' }, used);
          } else {
            url = ru;
            used.add(ru);
          }
        } else if (!url) {
          url = pickAvatarForInspectStoryRole(r, used);
        }
      }
    }
    if (!url) {
      url = pickAvatarForInspectUnboundName(display, used, String(c.id || `c-${idx}`));
    } else if (!used.has(url)) {
      used.add(url);
    }
    const avatarText = String(c.avatarText || display.charAt(0) || '联');
    return { ...c, avatarUrl: url, avatarText };
  });

  const nameToUrl = new Map<string, string>();
  contacts.forEach((c) => {
    const full = String(c.name || '').trim();
    const u = String(c.avatarUrl || '').trim();
    if (!full) return;
    nameToUrl.set(full, u);
    const base = full.replace(/（[^）]+）\s*$/u, '').trim();
    if (base && base !== full && !nameToUrl.has(base)) nameToUrl.set(base, u);
  });

  const chats = data.chats.map((ch, idx) => {
    let url = String(ch.avatarUrl || '').trim();
    const nm = String(ch.name || '').trim();
    if (!url) url = String(nameToUrl.get(nm) || '').trim();
    if (!url && pAv && (inspectContactIsPlayerRow(nm, playerAliases) || nm === canonPlayer)) {
      url = pAv;
      used.add(pAv);
    }
    if (!url) {
      const inferred = inferStoryRoleIdFromInspectContactName(nm, owner, allRoles, playerAliases);
      if (inferred) {
        const r = roleById.get(inferred);
        if (r) {
          const ru = String(r.avatarUrl || '').trim();
          if (ru && !used.has(ru)) {
            url = ru;
            used.add(ru);
          } else {
            url = pickAvatarForInspectStoryRole(ru && used.has(ru) ? { ...r, avatarUrl: '' } : r, used);
          }
        }
      }
    }
    if (!url) url = pickAvatarForInspectUnboundName(nm, used, String(ch.id || `ch-${idx}`));
    const avatarText = String(ch.avatarText || nm.charAt(0) || '联');
    return { ...ch, avatarUrl: url, avatarText };
  });

  return { ...data, contacts, chats };
};

/** 查手机场景下玩家头像：与主微信「我」页资料一致 */
const resolveInspectPlayerAvatarUrl = (_owner: StoryRole): string => {
  const sp = loadWeChatSelfProfile();
  return String(sp.avatarUrl || '').trim();
};

/** 合并人脉缺口 + 解析头像（缓存读出与 AI 生成后共用） */
const hydrateInspectWechatGeneratedData = (data: PhoneInspectWechatGeneratedData): PhoneInspectWechatGeneratedData => {
  const allRoles = loadStoryRoles();
  const owner = allRoles.find((r) => r.id === data.roleId);
  if (!owner) return data;
  const playerAvatarUrl = resolveInspectPlayerAvatarUrl(owner);
  const playerAliases = expandPlayerInspectAliases(owner);
  let next = mergeInspectWechatMissingRelationContacts(owner, allRoles, data);
  next = { ...next, contacts: repairInspectWechatContactBindings(owner, allRoles, next.contacts) };
  const deduped = dedupeInspectWechatContactsAndChats(owner, next.contacts, next.chats);
  next = { ...next, contacts: deduped.contacts, chats: deduped.chats };
  next = {
    ...next,
    contacts: ensureInspectContactsCoverChats(owner, allRoles, next.contacts, next.chats)
  };
  const stripped = stripInspectRelationParenSuffixFromInspectData(
    owner,
    allRoles,
    playerAliases,
    next.contacts,
    next.chats
  );
  next = { ...next, contacts: stripped.contacts, chats: stripped.chats };
  next = applyInspectWechatResolvedAvatars(next, allRoles, owner, playerAliases, playerAvatarUrl);
  next = {
    ...next,
    chats: (next.chats || []).map((ch) => {
      const messages = (ch.messages || []).map((mm, mi) =>
        normalizeInspectGeneratedChatMessage(mm as any, String((mm as any).id || `m-${ch.id}-${mi}`))
      );
      const last = messages[messages.length - 1];
      const lm = inspectGeneratedLastMessagePreview(last);
      return {
        ...ch,
        messages,
        lastMessage: lm || String(ch.lastMessage || '')
      };
    })
  };
  return next;
};

/** 其他角色手机里已生成、且 boundRoleId 指向 currentRoleId 的会话，供当前角色生成时衔接 */
const buildInspectWechatCrossRefBlock = (currentRoleId: string, allRoles: StoryRole[]): string => {
  if (!currentRoleId) return '';
  const cache = loadInspectWechatGeneratedCache();
  const blocks: string[] = [];
  for (const [ownerId, data] of Object.entries(cache)) {
    if (!data || ownerId === currentRoleId) continue;
    const owner = allRoles.find((r) => r.id === ownerId);
    const ownerLabel = owner?.wechatNickname || owner?.name || ownerId;
    const contact = (data.contacts || []).find((c) => c.boundRoleId === currentRoleId);
    if (!contact) continue;
    const titleOnOwnerPhone = String(contact.name || '').trim();
    const chat =
      (data.chats || []).find((ch) => String(ch.name || '').trim() === titleOnOwnerPhone) ||
      (data.chats || []).find((ch) =>
        (data.contacts || []).some((co) => co.boundRoleId === currentRoleId && String(co.name || '').trim() === String(ch.name || '').trim())
      );
    if (!chat?.messages?.length) continue;
    const currentRole = allRoles.find((r) => r.id === currentRoleId);
    const currentLabel = currentRole?.wechatNickname || currentRole?.name || '当前角色';
    const lines = chat.messages.slice(-35).map((m) => {
      const side = m.from === 'self' ? `对方手机持有者「${ownerLabel}」` : `在对方手机里显示为「${titleOnOwnerPhone}」的一方（即「${currentLabel}」）`;
      return `${m.time} [${side}] ${m.text}`;
    });
    blocks.push(
      `◆ 来源：角色「${ownerLabel}」的手机里，已生成过与你的会话。\n` +
        `◆ 对方通讯录中你的显示名：「${titleOnOwnerPhone}」\n` +
        `◆ 原记录视角：self = 「${ownerLabel}」，other = 「${titleOnOwnerPhone}」（即当前要生成数据的「${currentLabel}」）。\n` +
        `对话摘录（按时间顺序）：\n${lines.join('\n')}`
    );
  }
  return blocks.length ? blocks.join('\n\n') : '';
};

// 查手机-备忘录：轻量富文本（用于详情正文显示）
// 支持：
// **加粗**  *斜体*  __下划线__  ~~删除线~~  ==高亮==
// [color=#ff4d4f]自定义颜色[/color]
// 模型有时会直接输出 <span style="text-decoration:line-through"> 或 「词（划掉）」——在 HTML 转义前先归一为 ~~，避免界面上露出标签或括号舞台指示。

const escapeMemoPlainText = (s: string): string =>
  String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

/** 在转义前处理模型乱输出：HTML 删除线标签、口语「xx（划掉）」 */
const preprocessMemoArtifacts = (raw: string): string => {
  let t = String(raw || '');
  t = t.replace(/<span[^>]*text-decoration\s*:\s*line-through[^>]*>([\s\S]*?)<\/span>/giu, '~~$1~~');
  t = t.replace(/<del[^>]*>([\s\S]*?)<\/del>/giu, '~~$1~~');
  t = t.replace(/<s[^>]*>([\s\S]*?)<\/s>/giu, '~~$1~~');
  // 连续汉字/字母片段 +（划掉）→ 删除线（不写括号舞台词）
  for (let i = 0; i < 8; i++) {
    const next = t.replace(/([\u4e00-\u9fff·]{2,16}|[A-Za-z][A-Za-z0-9_-]{1,20})（\s*已?划掉\s*）/gu, '~~$1~~');
    if (next === t) break;
    t = next;
  }
  t = t.replace(/（\s*已?划掉\s*）/gu, '');
  return t;
};

const applyMemoRichMarkupOnEscaped = (escaped: string): string => {
  const withColor = escaped.replace(
    /\[color=(#[0-9a-fA-F]{3,8}|[a-zA-Z]+)\]([\s\S]*?)\[\/color\]/g,
    (_m, color, txt) => `<span style="color:${String(color)};">${txt}</span>`
  );
  return withColor
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/__(.+?)__/g, '<span style="text-decoration:underline;">$1</span>')
    .replace(/~~(.+?)~~/g, '<span style="text-decoration:line-through;opacity:.9;">$1</span>')
    .replace(/==(.+?)==/g, '<mark style="background:#fde68a;color:inherit;padding:0 1px;border-radius:2px;">$1</mark>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>');
};

const applyMemoRichInline = (line: string): string => {
  const pre = preprocessMemoArtifacts(String(line || ''));
  const escaped = escapeMemoPlainText(pre);
  return applyMemoRichMarkupOnEscaped(escaped);
};

const normalizeMemoBodyText = (text: string): string => {
  return String(text || '')
    .replace(/\[(?:br|BR)\]/g, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/\r\n?/g, '\n');
};

const splitPhotoDescAndThoughts = (desc: string): { cleanDesc: string; thoughts: string[] } => {
  const src = String(desc || '').trim();
  if (!src) return { cleanDesc: '', thoughts: [] };
  const thoughts: string[] = [];
  const clean = src
    .replace(/（([^）]*(?:内心|心想|想法|心理|OS|os|旁白)[^）]*)）/gu, (_m, g1) => {
      const t = String(g1 || '').trim();
      if (t) thoughts.push(t);
      return '';
    })
    .replace(/\(([^)]*(?:inner|thinking|os)[^)]*)\)/giu, (_m, g1) => {
      const t = String(g1 || '').trim();
      if (t) thoughts.push(t);
      return '';
    })
    .replace(/\s{2,}/g, ' ')
    .trim();
  return { cleanDesc: clean, thoughts };
};

const applyMemoStrikeInline = (line: string): string => {
  const pre = preprocessMemoArtifacts(String(line || ''));
  const escaped = escapeMemoPlainText(pre);
  // 将“（划掉xxx）/ [划掉xxx] / (划掉xxx)”转为 ~~，再走统一富文本（避免在此处插入 HTML 后又二次转义）
  const withStrike = escaped
    .replace(/（\s*(?:已?划掉|划线删除|删除线|划去|作废)\s*([^）]+?)\s*）/giu, '~~$1~~')
    .replace(/\[\s*(?:已?划掉|划线删除|删除线|划去|作废)\s*([^\]]+?)\s*\]/giu, '~~$1~~')
    .replace(/\(\s*(?:已?划掉|划线删除|删除线|划去|作废)\s*([^)]+?)\s*\)/giu, '~~$1~~');
  return applyMemoRichMarkupOnEscaped(withStrike);
};

const renderMemoRichText = (text: string): React.ReactNode => {
  const lines = normalizeMemoBodyText(text).split('\n');
  return (
    <>
      {lines.map((line, idx) => {
        const checklistMatch = line.match(/^\s*(?:\d+[.)、]\s*)?(?:-\s*)?\[(x|X| )\]\s*(.+)$/u);
        const checkedDotMatch = line.match(
          /^\s*(?:\d+[.)、]\s*)?(?:\[color=[^\]]+\])?(?:●|🟡|🟨|✅)(?:\[\/color\])?\s*(.+)$/u
        );
        const uncheckedDotMatch = line.match(/^\s*(?:\d+[.)、]\s*)?(?:○|⚪|⬜)\s*(.+)$/u);
        const isChecked = !!checklistMatch && /x/i.test(checklistMatch[1] || '');
        const checklistText = checklistMatch?.[2] || checkedDotMatch?.[1] || uncheckedDotMatch?.[1] || '';
        const isChecklistLine = !!(checklistMatch || checkedDotMatch || uncheckedDotMatch);

        if (isChecklistLine) {
          const checked = checklistMatch ? isChecked : !!checkedDotMatch;
          return (
            <div
              key={`memo-line-${idx}`}
              style={{
                display: 'flex',
                alignItems: 'flex-start',
                gap: 10,
                margin: '4px 0'
              }}
            >
              <span
                aria-hidden="true"
                style={{
                  marginTop: 2,
                  width: 22,
                  height: 22,
                  minWidth: 22,
                  borderRadius: '50%',
                  boxSizing: 'border-box',
                  border: checked ? '1px solid #eab308' : '1.7px solid #d1d5db',
                  backgroundColor: checked ? '#eab308' : '#ffffff',
                  color: '#ffffff',
                  display: 'inline-flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 14,
                  lineHeight: 1,
                  fontWeight: 800
                }}
              >
                {checked ? '✓' : ''}
              </span>
              <span
                style={{ flex: 1 }}
                dangerouslySetInnerHTML={{
                  __html: checklistText ? applyMemoRichInline(checklistText) : '&nbsp;'
                }}
              />
            </div>
          );
        }

        return (
          <React.Fragment key={`memo-line-${idx}`}>
            <span
              dangerouslySetInnerHTML={{
                __html: line ? applyMemoStrikeInline(line) : '&nbsp;'
              }}
            />
            {idx < lines.length - 1 ? <br /> : null}
          </React.Fragment>
        );
      })}
    </>
  );
};

const getMemoPreviewText = (text: string): string => {
  const raw = normalizeMemoBodyText(text);
  if (!raw.trim()) return '';
  const firstLine = raw
    .split('\n')
    .map((s) => s.trim())
    .find((s) => s.length > 0) || '';
  if (!firstLine) return '';
  const plain = preprocessMemoArtifacts(firstLine)
    .replace(/<[^>]+>/g, '')
    .replace(/\[color=(#[0-9a-fA-F]{3,8}|[a-zA-Z]+)\]([\s\S]*?)\[\/color\]/g, '$2')
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/__(.+?)__/g, '$1')
    .replace(/~~(.+?)~~/g, '$1')
    .replace(/==(.+?)==/g, '$1')
    .replace(/\*(.+?)\*/g, '$1')
    .trim();
  return plain;
};

