function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function ensureCount<T>(arr: T[], targetMin: number, targetMax: number, create: (idx: number, seed?: T) => T): T[] {
  const src = Array.isArray(arr) ? [...arr] : [];
  const target = Math.max(targetMin, Math.min(targetMax, src.length >= targetMin ? src.length : randomInt(targetMin, targetMax)));
  if (!src.length) src.push(create(0));
  let i = 0;
  while (src.length < target) {
    src.push(create(src.length, src[i % src.length]));
    i++;
  }
  return src.slice(0, targetMax);
}

function inferShoppingOrderTargetMin(role: any, roleId: string): number {
  const seedText = `${role?.name || ''}|${role?.wechatNickname || ''}|${role?.description || ''}|${role?.persona || ''}`.toLowerCase();
  const has = (re: RegExp) => re.test(seedText);
  let score = 0;

  // 低消费/少购物：拉低
  if (has(/不爱购物|很少购物|几乎不买|不网购|极简|节俭|省钱|断舍离|清心寡欲/)) score -= 3;
  if (has(/学生|在读|月光不足|拮据|兼职|打工人穷|精打细算/)) score -= 1;

  // 高消费/爱买：拉高
  if (has(/爱买|爱逛|剁手|冲动消费|网购达人|收藏癖|种草|爱尝新|爱折腾/)) score += 3;
  if (has(/白领|金融|投行|创业|老板|富二代|高管|奢侈|高消费|生活品质/)) score += 2;
  if (has(/潮牌|香氛|护肤|彩妆|穿搭|球鞋|摄影|数码|音响|机械键盘|露营|健身/)) score += 1;

  // 角色ID做微扰，避免所有角色落在同一档
  let h = 0;
  const s = String(roleId || 'role');
  for (let i = 0; i < s.length; i++) h = (h * 33 + s.charCodeAt(i)) | 0;
  const jitter = Math.abs(h) % 3; // 0~2

  // 映射到目标最小订单数（同时给 normalize 的状态分桶留余量）
  // score: -4..+6 -> target: 6..18
  const base = 10;
  const target = base + score * 2 + jitter;
  return Math.max(6, Math.min(18, target));
}

function detectShoppingMissing(raw: any, targetMinOrders: number): string[] {
  const miss: string[] = [];
  const norm = (s: any) =>
    String(s || '')
      .toLowerCase()
      .replace(/\s+/g, '')
      .replace(/[，。、“”‘’！？!?,.:：;；\-—_()（）【】\[\]{}<>《》'"`~|\\/]/g, '');
  const orders = raw?.orders || {};
  const pay = Array.isArray(orders.pay) ? orders.pay.length : 0;
  const ship = Array.isArray(orders.ship) ? orders.ship.length : 0;
  const recv = Array.isArray(orders.recv) ? orders.recv.length : 0;
  const refund = Array.isArray(orders.refund) ? orders.refund.length : 0;
  const review = Array.isArray(orders.review) ? orders.review.length : 0;
  const total = pay + ship + recv + refund + review;
  if (total < targetMinOrders) miss.push(`订单总量仅 ${total} 条（目标至少 ${targetMinOrders} 条）`);
  const bucketCounts = [pay, ship, recv, refund, review];
  const nonZero = bucketCounts.filter((n) => n > 0).length;
  if (nonZero < 2) miss.push('订单状态分布过于单一（至少覆盖 2 类状态）');
  const distinctCounts = new Set(bucketCounts);
  if (distinctCounts.size <= 1) miss.push('订单状态分布过于整齐（请生成不规则数量）');

  const chats = Array.isArray(raw?.messages?.storeChats) ? raw.messages.storeChats : [];
  if (chats.length < 3) miss.push('客服会话少于 3 条');
  const noThread = chats.filter((c: any) => !Array.isArray(c?.thread) || c.thread.length < 2).length;
  if (noThread > 0) miss.push(`有 ${noThread} 条客服会话缺少有效聊天记录`);
  const hasOrdered = chats.some((c: any) => !!c?.ordered);
  const hasUnordered = chats.some((c: any) => c?.ordered === false);
  if (!hasOrdered) miss.push('缺少已下单客服会话');
  if (!hasUnordered) miss.push('缺少未下单/未付款客服会话');

  const requiredBuckets: Array<'pay' | 'ship' | 'recv' | 'refund'> = ['pay', 'ship', 'recv', 'refund'];
  const orderRefs = requiredBuckets.flatMap((k) =>
    (Array.isArray(orders[k]) ? orders[k] : []).map((o: any) => ({
      bucket: k,
      shop: norm(o?.shopName),
      product: norm(o?.products?.[0]?.title)
    }))
  );
  const covered = new Set<string>();
  let orderedButUnmatched = 0;
  chats.forEach((c: any) => {
    if (!c?.ordered) return;
    const cShop = norm(c?.shopName);
    const cProd = norm(c?.productTitle);
    let hit = orderRefs.find((r) => r.shop && r.shop === cShop && r.product && r.product === cProd);
    if (!hit) hit = orderRefs.find((r) => r.shop && r.shop === cShop);
    if (hit) covered.add(hit.bucket);
    else orderedButUnmatched += 1;
  });
  if (orderedButUnmatched > 0) miss.push(`有 ${orderedButUnmatched} 条“已下单客服会话”无法匹配任何订单`);
  requiredBuckets.forEach((k) => {
    const hasOrdersInBucket = Array.isArray(orders[k]) && orders[k].length > 0;
    if (hasOrdersInBucket && !covered.has(k)) {
      const label = k === 'pay' ? '待付款' : k === 'ship' ? '待发货' : k === 'recv' ? '待收货' : '退款/售后';
      miss.push(`缺少「${label}」订单对应的客服会话`);
    }
  });
  return miss;
}

function detectStoreChatSimilarityIssues(raw: any, threshold = 0.84): string[] {
  const chats = Array.isArray(raw?.messages?.storeChats) ? raw.messages.storeChats : [];
  const normalize = (s: string): string =>
    String(s || '')
      .toLowerCase()
      .replace(/\s+/g, '')
      .replace(/[，。、“”‘’！？!?,.:：;；\-—_()（）【】\[\]{}<>《》'"`~|\\/]/g, '');
  const sig = (c: any): string => {
    const t = Array.isArray(c?.thread)
      ? c.thread.map((x: any) => `${x?.from || ''}:${x?.text || ''}`).join('|')
      : '';
    return normalize(t);
  };
  const jaccard = (a: string, b: string): number => {
    if (!a || !b) return 0;
    if (a === b) return 1;
    const sa = new Set(Array.from(a));
    const sb = new Set(Array.from(b));
    let inter = 0;
    sa.forEach((ch) => {
      if (sb.has(ch)) inter += 1;
    });
    const union = sa.size + sb.size - inter;
    return union > 0 ? inter / union : 0;
  };
  const issues: string[] = [];
  for (let i = 0; i < chats.length; i += 1) {
    for (let j = i + 1; j < chats.length; j += 1) {
      const a = sig(chats[i]);
      const b = sig(chats[j]);
      const sim = jaccard(a, b);
      if (sim >= threshold) {
        issues.push(
          `店铺会话相似度过高：${String(chats[i]?.shopName || `#${i + 1}`)} 与 ${String(chats[j]?.shopName || `#${j + 1}`)}（${sim.toFixed(2)}）`
        );
      }
    }
  }
  return issues;
}

function detectShoppingQualityIssues(raw: any): string[] {
  const issues: string[] = [];
  const norm = (s: any) =>
    String(s || '')
      .toLowerCase()
      .replace(/\s+/g, '')
      .replace(/[，。、“”‘’！？!?,.:：;；\-—_()（）【】\[\]{}<>《》'"`~|\\/]/g, '');
  const uniqueRate = (arr: any[], keyFn: (x: any) => string): number => {
    if (!Array.isArray(arr) || arr.length === 0) return 1;
    const seen = new Set<string>();
    arr.forEach((x) => seen.add(keyFn(x)));
    return seen.size / arr.length;
  };
  const orders = raw?.orders || {};
  const allOrders = ([] as any[]).concat(orders.pay || [], orders.ship || [], orders.recv || [], orders.refund || [], orders.review || []);
  const orderRate = uniqueRate(allOrders, (o) => `${norm(o?.shopName)}|${norm(o?.products?.[0]?.title)}|${norm(o?.status)}|${norm(o?.actualPay)}`);
  if (orderRate < 0.7) issues.push(`订单重复率过高（唯一率${orderRate.toFixed(2)}）`);

  const reviews = Array.isArray(raw?.reviews) ? raw.reviews : [];
  const reviewRate = uniqueRate(reviews, (r) => `${norm(r?.title)}|${norm(r?.productTitle)}|${norm(r?.dateText)}`);
  if (reviewRate < 0.75) issues.push(`评价重复率过高（唯一率${reviewRate.toFixed(2)}）`);

  const fps = Array.isArray(raw?.footprints) ? raw.footprints : [];
  const fpRate = uniqueRate(fps, (f) => `${norm(f?.title)}|${norm(f?.priceText)}`);
  if (fpRate < 0.75) issues.push(`足迹重复率过高（唯一率${fpRate.toFixed(2)}）`);

  const follows = Array.isArray(raw?.followStores) ? raw.followStores : [];
  const followRate = uniqueRate(follows, (f) => norm(f?.name));
  if (followRate < 0.8) issues.push(`关注店铺重复率过高（唯一率${followRate.toFixed(2)}）`);
  const genericFollow = follows.filter((f: any) => /精选店铺|店铺\d+/.test(String(f?.name || ''))).length;
  if (genericFollow > 0) issues.push(`关注店铺名称泛化（${genericFollow}条）`);
  const missingOrderShop = allOrders.filter((o: any) => !String(o?.shopName || '').trim()).length;
  if (missingOrderShop > 0) issues.push(`订单缺少店铺名（${missingOrderShop}条）`);
  const chats = Array.isArray(raw?.messages?.storeChats) ? raw.messages.storeChats : [];
  const missingChatShop = chats.filter((c: any) => !String(c?.shopName || '').trim()).length;
  if (missingChatShop > 0) issues.push(`客服会话缺少店铺名（${missingChatShop}条）`);
  {
    const orderRefs = allOrders.map((o: any) => ({
      shop: norm(o?.shopName),
      product: norm(o?.products?.[0]?.title)
    }));
    const orderedButUnmatched = chats.filter((c: any) => {
      if (!c?.ordered) return false;
      const cShop = norm(c?.shopName);
      const cProd = norm(c?.productTitle);
      return !orderRefs.some((r: any) => (r.shop && r.shop === cShop && (!cProd || !r.product || r.product === cProd)));
    }).length;
    if (orderedButUnmatched > 0) issues.push(`已下单客服会话与订单不一致（${orderedButUnmatched}条）`);
  }
  const missingFollowShop = follows.filter((f: any) => !String(f?.name || '').trim()).length;
  if (missingFollowShop > 0) issues.push(`关注店铺缺少名称（${missingFollowShop}条）`);

  return issues;
}

function mergeShoppingPatch(base: any, patch: any): any {
  if (patch === undefined) return base;
  if (patch === null) return null;
  if (Array.isArray(patch)) return patch;
  if (typeof patch !== 'object') return patch;
  const b = base && typeof base === 'object' && !Array.isArray(base) ? base : {};
  const out: Record<string, any> = { ...b };
  Object.keys(patch).forEach((k) => {
    out[k] = mergeShoppingPatch((b as any)[k], (patch as any)[k]);
  });
  return out;
}

function normalizeGeneratedShoppingSnapshot(roleId: string, role: any, raw: any): any {
  const normalizeKey = (v: any): string =>
    String(v ?? '')
      .replace(/\s+/g, ' ')
      .trim()
      .toLowerCase();
  const ensureUniqueLabel = (base: string, index: number): string => {
    const t = String(base || '').trim() || '店铺';
    return index > 0 ? `${t} ${index + 1}` : t;
  };
  const hashOf = (s: string): number => {
    let h = 0;
    for (let i = 0; i < s.length; i += 1) h = (h * 33 + s.charCodeAt(i)) | 0;
    return Math.abs(h);
  };
  const normalizeReviewCommentNodes = (nodes: any[], keyPrefix: string): any[] => {
    if (!Array.isArray(nodes)) return [];
    return nodes.map((node, idx) => {
      const src = node && typeof node === 'object' ? node : {};
      const authorRaw = src.author && typeof src.author === 'object' ? src.author : {};
      const baseName = String(authorRaw.displayName || authorRaw.name || src.displayName || src.name || '').trim();
      const safeName = baseName || `网友${idx + 1}`;
      const replyToRaw = String(src.replyToName || src.replyTo?.name || src.replyTo || '').trim();
      const replyToName = replyToRaw && replyToRaw === safeName ? '' : replyToRaw;
      return {
        ...src,
        id: String(src.id || `${keyPrefix}-c${idx + 1}`),
        author: {
          ...authorRaw,
          displayName: safeName,
          isRole: false,
          role: false
        },
        replyToName: replyToName || undefined,
        replies: normalizeReviewCommentNodes(src.replies || [], `${keyPrefix}-c${idx + 1}`)
      };
    });
  };

  const data = raw && typeof raw === 'object' ? { ...raw } : {};
  const nowTag = Date.now();
  const targetMinOrders = inferShoppingOrderTargetMin(role, roleId);
  const ordersRaw = (data.orders && typeof data.orders === 'object') ? { ...data.orders } : {};
  const allSeedOrders: any[] = []
    .concat(ordersRaw.pay || [], ordersRaw.ship || [], ordersRaw.recv || [], ordersRaw.refund || [], ordersRaw.review || [])
    .filter(Boolean);
  const fallbackOrder = allSeedOrders[0] || {
    id: `o-${nowTag}`,
    shopName: '官方旗舰店',
    shopTag: 'tb',
    status: '待发货',
    products: [{ title: '精选商品', spec: '默认规格', price: '¥99.00', qty: 1 }],
    actualPay: '¥99.00',
    actions: ['联系商家']
  };

  const makeOrder = (status: string, key: 'pay' | 'ship' | 'recv' | 'refund' | 'review', idx: number, seed?: any) => {
    const base = seed || fallbackOrder;
    const p0 = base?.products?.[0] || fallbackOrder.products[0];
    const o: any = {
      ...base,
      id: `${base.id || key}-${idx + 1}-${nowTag}`,
      shopName: String(base.shopName || '').trim(),
      status,
      products: Array.isArray(base.products) && base.products.length ? base.products : [p0],
      actualPay: base.actualPay || p0.price || '¥99.00'
    };
    if (key === 'pay') {
      o.actions = ['联系商家', '取消订单', '立即付款'];
      o.primaryAction = '立即付款';
    }
    if (key === 'ship') {
      o.actions = ['联系商家', '催发货'];
      o.primaryAction = '催发货';
    }
    if (key === 'recv') {
      o.actions = ['查看物流', '确认收货', '联系商家'];
      o.primaryAction = '确认收货';
    }
    if (key === 'review') {
      o.actions = ['评价', '联系商家'];
      o.primaryAction = '评价';
    }
    if (key === 'refund') {
      o.actions = ['联系商家', '退款详情'];
      o.primaryAction = '退款详情';
      o.afterSalesType = o.afterSalesType || 'return_refund';
      o.returnTrackingNo = String(o.returnTrackingNo || `SF${String(Math.abs(nowTag + idx)).slice(0, 10)}`);
      o.refundReason = String(o.refundReason || '质量问题');
      o.evidenceNote = String(o.evidenceNote || '补充说明：已上传实拍图与细节图，申请售后处理。');
      o.afterSalesNodes = Array.isArray(o.afterSalesNodes) && o.afterSalesNodes.length
        ? o.afterSalesNodes
        : [
            { time: '2023-10-26 11:30', title: '买家发起申请', detail: '已提交售后申请。', done: true },
            { time: '2023-10-26 16:00', title: '商家处理中', detail: '商家正在审核售后申请。', done: false, current: true },
            { time: '2023-10-27 09:30', title: '待平台确认', detail: '平台待确认退款结果。', done: false }
          ];
    }
    if (key === 'ship' || key === 'recv') {
      o.trackingNo = String(o.trackingNo || `LUMI${String(Math.abs(nowTag + idx)).slice(0, 10)}`);
      o.logisticsTimeline = Array.isArray(o.logisticsTimeline) && o.logisticsTimeline.length
        ? o.logisticsTimeline
        : [
            { time: '10-26 10:20', title: '运输中', body: '包裹已发往下一中转站。', current: true },
            { time: '10-26 08:10', body: '包裹已离开发货地。' },
            { time: '10-25 22:00', body: '包裹已揽收。' }
          ];
    }
    return o;
  };

  const keys: Array<'pay' | 'ship' | 'recv' | 'refund' | 'review'> = ['pay', 'ship', 'recv', 'refund', 'review'];
  const targets: Record<'pay' | 'ship' | 'recv' | 'refund' | 'review', number> = {
    pay: 0,
    ship: 0,
    recv: 0,
    refund: 0,
    review: 0
  };
  // 不规则分布：仍保持非均匀，但核心链路（待付款/待发货/待收货/退款）至少各 1 条。
  {
    let left = targetMinOrders;
    for (let i = 0; i < 5; i += 1) {
      const k = keys[i];
      const remainBuckets = 5 - i;
      const cap = Math.min(5, left);
      let n = 0;
      if (remainBuckets === 1) {
        n = cap;
      } else {
        const minKeep = 0;
        const maxForThis = Math.max(0, Math.min(cap, left - minKeep * (remainBuckets - 1)));
        n = randomInt(0, maxForThis);
      }
      targets[k] = n;
      left -= n;
    }
    // 若随机后不足，按轮询补齐，但避免强行平均。
    let guard = 0;
    while (left > 0 && guard < 60) {
      const k = keys[(hashOf(`${roleId}|${guard}`) + guard) % keys.length];
      if (targets[k] < 5) {
        targets[k] += 1;
        left -= 1;
      }
      guard += 1;
    }
    // 核心四类状态至少各有 1 条订单
    (['pay', 'ship', 'recv', 'refund'] as const).forEach((k) => {
      if (targets[k] > 0) return;
      targets[k] = 1;
    });
    // 若总量超出，则优先从 review 或最大桶回收，保持核心四类存在
    let totalNow = keys.reduce((s, k) => s + targets[k], 0);
    while (totalNow > targetMinOrders) {
      const candidates = keys
        .slice()
        .sort((a, b) => targets[b] - targets[a])
        .filter((k) => !(['pay', 'ship', 'recv', 'refund'] as const).includes(k as any) || targets[k] > 1);
      const pick = candidates[0];
      if (!pick || targets[pick] <= 0) break;
      targets[pick] -= 1;
      totalNow -= 1;
    }

    // 至少两个状态有数据（更真实）
    const nonZeroKeys = keys.filter((k) => targets[k] > 0);
    if (nonZeroKeys.length < 2) {
      const k1 = 'ship';
      const k2 = 'recv';
      if (targets[k1] === 0) targets[k1] = 1;
      if (targets[k2] === 0) targets[k2] = 1;
      // 总量超出时从最大桶回收
      let totalNow = keys.reduce((s, k) => s + targets[k], 0);
      while (totalNow > targetMinOrders) {
        const largest = keys.slice().sort((a, b) => targets[b] - targets[a])[0];
        if (targets[largest] > 0) {
          targets[largest] -= 1;
          totalNow -= 1;
        } else {
          break;
        }
      }
    }
  }
  keys.forEach((k) => {
    const arrSrc = Array.isArray(ordersRaw[k]) ? [...ordersRaw[k]] : [];
    const target = Math.max(targets[k], Math.min(arrSrc.length, 5));
    while (arrSrc.length < target) {
      arrSrc.push(
        makeOrder(
        k === 'pay' ? '待付款' : k === 'ship' ? '待发货' : k === 'recv' ? '待收货' : k === 'refund' ? '退款中' : '交易成功',
        k,
          arrSrc.length,
          arrSrc[0]
        )
      );
    }
    ordersRaw[k] = arrSrc.slice(0, 5);
  });

  // 强约束各状态按钮，避免模型/旧数据夹带多余按钮
  const sanitizeActionsByStatus = (o: any): any => {
    const st = String(o?.status || '').trim();
    const keepUnique = (arr: string[]) => Array.from(new Set(arr.map((x) => String(x || '').trim()).filter(Boolean)));
    if (st === '待付款') {
      const actions = keepUnique(['联系商家', '取消订单', '立即付款']);
      return { ...o, actions, primaryAction: '立即付款' };
    }
    if (st === '待发货') {
      const actions = keepUnique(['联系商家', '催发货']);
      return { ...o, actions, primaryAction: '催发货' };
    }
    if (/退款|售后|介入|换货/.test(st) || st === '退款中') {
      const actions = keepUnique(['联系商家', '退款详情']);
      return { ...o, actions, primaryAction: '退款详情' };
    }
    return o;
  };
  (['pay', 'ship', 'recv', 'refund', 'review'] as const).forEach((k) => {
    const arr = Array.isArray(ordersRaw[k]) ? ordersRaw[k] : [];
    const seen = new Map<string, number>();
    ordersRaw[k] = arr.map((o: any, idx: number) => {
      const p0 = o?.products?.[0] || {};
      const sign = `${normalizeKey(o?.shopName)}|${normalizeKey(p0?.title)}|${normalizeKey(p0?.spec)}|${normalizeKey(o?.actualPay)}|${normalizeKey(o?.status)}`;
      const hit = seen.get(sign) || 0;
      seen.set(sign, hit + 1);
      if (hit === 0) return sanitizeActionsByStatus(o);
      const nextShop = String(o?.shopName || '').trim() || ensureUniqueLabel('店铺', idx + hit);
      const nextProducts = Array.isArray(o?.products)
        ? o.products.map((p: any, pIdx: number) =>
            pIdx === 0
              ? {
                  ...p,
                  spec: String(p?.spec || '').trim()
                    ? `${String(p.spec).trim()} · 第${hit + 1}单`
                    : `默认规格 · 第${hit + 1}单`
                }
              : p
          )
        : o?.products;
      return sanitizeActionsByStatus({ ...o, shopName: nextShop, products: nextProducts });
    });
  });
  data.orders = ordersRaw;

  const shopsForChat = ([] as any[]).concat(
    ordersRaw.pay || [],
    ordersRaw.ship || [],
    ordersRaw.recv || [],
    ordersRaw.refund || [],
    ordersRaw.review || []
  );
  const messagesRaw = (data.messages && typeof data.messages === 'object') ? { ...data.messages } : {};
  const sourceChats = Array.isArray(messagesRaw.storeChats) ? messagesRaw.storeChats : [];
  const requiredOrderRefs = ([] as any[]).concat(
    (ordersRaw.pay || []).map((o: any) => ({ bucket: 'pay', order: o })),
    (ordersRaw.ship || []).map((o: any) => ({ bucket: 'ship', order: o })),
    (ordersRaw.recv || []).map((o: any) => ({ bucket: 'recv', order: o })),
    (ordersRaw.refund || []).map((o: any) => ({ bucket: 'refund', order: o }))
  );
  const normShop = (s: any) =>
    String(s || '')
      .toLowerCase()
      .replace(/\s+/g, '')
      .replace(/[，。、“”‘’！？!?,.:：;；\-—_()（）【】\[\]{}<>《》'"`~|\\/]/g, '');
  const findOrderRefForChat = (shopName: string, productTitle: string): any | null => {
    const sKey = normShop(shopName);
    const pKey = normShop(productTitle);
    let hit = requiredOrderRefs.find(
      (x: any) => normShop(x?.order?.shopName) === sKey && normShop(x?.order?.products?.[0]?.title) === pKey
    );
    if (hit) return hit;
    hit = requiredOrderRefs.find((x: any) => normShop(x?.order?.shopName) === sKey);
    return hit || null;
  };
  if (sourceChats.length > 0) {
    messagesRaw.storeChats = sourceChats.map((c: any, idx: number) => {
      const thread = Array.isArray(c?.thread) ? c.thread : [];
      const rawShop = String(c?.shopName || '').trim();
      const rawProduct = String(c?.productTitle || '').trim() || rawShop || '咨询商品';
      const matchedOrderRef = findOrderRefForChat(rawShop, rawProduct);
      const matchedOrder = matchedOrderRef?.order;
      const matchedP0 = matchedOrder?.products?.[0] || {};
      return {
        id: String(c?.id || `sc-${idx + 1}-${nowTag}`),
        shopName: String(matchedOrder?.shopName || rawShop).trim(),
        preview: String(c?.preview || '').trim() || '店铺客服已回复。',
        time: String(c?.time || '').trim() || ['刚刚', '5分钟前', '11:05', '昨天'][idx % 4],
        unread: Number(c?.unread ?? 0),
        // 规则：只有能匹配到真实订单的会话，才标记为 ordered=true；其余视为“咨询型未下单会话”。
        ordered: !!matchedOrder,
        productTitle: String(matchedP0?.title || rawProduct).trim() || '咨询商品',
        thread:
          thread
            .map((t: any, tIdx: number) => ({
              from: t?.from === 'staff' ? 'staff' : 'role',
              text: String(t?.text || '').trim(),
              time: String(t?.time || '').trim() || `09:${String(20 + tIdx).padStart(2, '0')}`
            }))
            .filter((t: any) => !!t.text)
      };
    });
  } else {
    // 不再本地生成兜底店铺会话，强制要求由模型提供
    messagesRaw.storeChats = [];
  }
  {
    const seen = new Map<string, number>();
    messagesRaw.storeChats = (messagesRaw.storeChats || []).map((c: any, idx: number) => {
      const key = `${normalizeKey(c?.shopName)}|${normalizeKey(c?.preview)}|${normalizeKey(c?.productTitle)}`;
      const hit = seen.get(key) || 0;
      seen.set(key, hit + 1);
      if (hit === 0) return c;
      return {
        ...c,
        shopName: ensureUniqueLabel(c?.shopName || `店铺${idx + 1}`, hit),
        id: String(c?.id || `sc-${idx + 1}-${nowTag}`)
      };
    });
  }
  {
    // 若仍有 ordered=true 但匹配不到订单的脏数据，强制降级为咨询会话，避免“未下单却像已下单”的离谱展示。
    messagesRaw.storeChats = (messagesRaw.storeChats || []).map((c: any) => {
      if (!c?.ordered) return c;
      const hit = findOrderRefForChat(String(c?.shopName || ''), String(c?.productTitle || ''));
      if (hit) return c;
      return { ...c, ordered: false };
    });
  }
  data.messages = messagesRaw;

  data.reviews = ensureCount(data.reviews || [], 3, 5, (idx, seed: any) => {
    const s = seed || {};
    const liked = Math.max(3, Number(s.liked || 0) || randomInt(3, 5));
    const modelLikeUsers = Array.isArray(s.likeUsers) ? s.likeUsers : [];
    const likeUsers = modelLikeUsers
      .filter((u: any) => u && typeof u === 'object')
      .map((u: any, i: number) => ({
        id: String(u?.id || `u-${idx + 1}-${i + 1}`),
        displayName: String(u?.displayName || u?.name || u?.nickname || '').trim(),
        anonymous: !!u?.anonymous
      }))
      .filter((u: any) => !!u.displayName);
    const comments = ensureCount(Array.isArray(s.comments) ? s.comments : [], 3, 5, (i, c: any) => ({
      id: `c-${idx + 1}-${i + 1}`,
      author: { displayName: c?.author?.displayName || `网友${i + 1}`, isRole: false, role: false },
      timeText: c?.timeText || `${randomInt(10, 59)}分钟前`,
      contentText: c?.contentText || c?.text || '质感不错，细节也到位。',
      likeCount: Number(c?.likeCount ?? randomInt(0, 8))
    }));
    return {
      id: s.id || `r-${idx + 1}-${nowTag}`,
      title: s.title || '整体体验不错，外观和手感都在线。',
      dateText: s.dateText || '2023-10-26',
      productTitle: s.productTitle || '精选商品',
      images: Array.isArray(s.images) && s.images.length ? s.images : [{ url: '', desc: '外观细节：表面纹理细腻，边缘做工规整。' }],
      viewed: Number(s.viewed ?? randomInt(200, 2000)),
      liked,
      commented: comments.length,
      comments: normalizeReviewCommentNodes(comments, `r-${idx + 1}-${nowTag}`),
      likeUsers
    };
  });
  {
    const seen = new Map<string, number>();
    data.reviews = (data.reviews || []).map((r: any, idx: number) => {
      const key = `${normalizeKey(r?.title)}|${normalizeKey(r?.productTitle)}|${normalizeKey(r?.dateText)}`;
      const hit = seen.get(key) || 0;
      seen.set(key, hit + 1);
      if (hit === 0) return r;
      return {
        ...r,
        title: `${String(r?.title || '购物体验').trim()}（补充${hit + 1}）`
      };
    });
  }

  data.footprints = ensureCount(data.footprints || [], 3, 8, (idx, seed: any) => {
    const fromOrder = shopsForChat[idx % Math.max(1, shopsForChat.length)] || {};
    return {
      id: seed?.id || `fp-${idx + 1}-${nowTag}`,
      title: seed?.title || String(fromOrder?.products?.[0]?.title || `浏览商品 ${idx + 1}`),
      desc: seed?.desc || `你浏览了 ${String(fromOrder?.shopName || '该店铺')} 的相关商品。`,
      viewedText: seed?.viewedText || `看过 ${randomInt(1, 8)} 次`,
      viewedAtText: seed?.viewedAtText || ['10:30', '09:15', '昨天', '前天'][idx % 4],
      priceText: seed?.priceText || String(fromOrder?.products?.[0]?.price || `¥${randomInt(99, 9999)}`)
    };
  });

  data.followStores = Array.isArray(data.followStores) ? data.followStores : [];

  return data;
}

/** 清除本机全部「查手机」生成缓存（所有角色）：微信快照、备忘录、睡眠记录 */
const clearAllPhoneInspectGeneratedStorage = () => {
  try {
    appStorage.removeItem(PHONE_INSPECT_WECHAT_CACHE_KEY);
    for (const key of appStorage.keys()) {
      if (
        key.startsWith(PHONE_INSPECT_MEMO_STORAGE_PREFIX) ||
        key.startsWith(PHONE_INSPECT_SLEEP_STORAGE_PREFIX) ||
        key.startsWith(PHONE_INSPECT_SHOPPING_STORAGE_PREFIX)
      ) {
        appStorage.removeItem(key);
      }
    }
  } catch {
    // ignore
  }
};

const normalizeMemoDedupKey = (title: string, body: string): string => {
  const t = String(title || '').trim().toLowerCase();
  const b = String(body || '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
  return `${t}__${b}`;
};

const normalizeMemoTitleKey = (title: string): string =>
  String(title || '')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();

const normalizeMemoBodyKey = (body: string): string =>
  String(body || '')
    .toLowerCase()
    .replace(/\[(?:br|BR)\]/g, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/\s+/g, '')
    .replace(/[，。、“”‘’！？!?,.:：;；\-—_()（）【】\[\]{}<>《》'"`~|\\/]/g, '');

const calcMemoBodySimilarity = (a: string, b: string): number => {
  const aa = normalizeMemoBodyKey(a);
  const bb = normalizeMemoBodyKey(b);
  if (!aa || !bb) return 0;
  if (aa === bb) return 1;

  // 包含关系优先：适合“v2.1 -> v2.2”这类增删改
  const minLen = Math.min(aa.length, bb.length);
  const maxLen = Math.max(aa.length, bb.length);
  const containScore = (aa.includes(bb) || bb.includes(aa)) ? minLen / Math.max(1, maxLen) : 0;

  // 字符集合 Jaccard（对中文短句更鲁棒）
  const sa = new Set(Array.from(aa));
  const sb = new Set(Array.from(bb));
  let inter = 0;
  sa.forEach((ch) => {
    if (sb.has(ch)) inter += 1;
  });
  const union = sa.size + sb.size - inter;
  const jaccard = union > 0 ? inter / union : 0;

  return Math.max(containScore, jaccard);
};

const parseMemoTimeToTimestamp = (raw: string | undefined | null): number | null => {
  const s = String(raw || '').trim();
  if (!s) return null;
  const direct = new Date(s).getTime();
  if (Number.isFinite(direct)) return direct;
  const m = s.match(
    /(\d{4})[\/\-.年](\d{1,2})[\/\-.月](\d{1,2})\s*(?:[日号]?\s*)?(?:(\d{1,2})[:：](\d{1,2}))?/u
  );
  if (!m) return null;
  const yyyy = Number(m[1]);
  const mon = Number(m[2]);
  const dd = Number(m[3]);
  const hh = Number(m[4] ?? '0');
  const mi = Number(m[5] ?? '0');
  if (![yyyy, mon, dd, hh, mi].every(Number.isFinite)) return null;
  const ts = new Date(yyyy, mon - 1, dd, hh, mi, 0, 0).getTime();
  return Number.isFinite(ts) ? ts : null;
};

const formatMemoDateText = (ts: number): { updatedAt: string; detailTime: string } => {
  const d = new Date(ts);
  const yyyy = d.getFullYear();
  const mon = d.getMonth() + 1;
  const dd = d.getDate();
  const hh = String(d.getHours()).padStart(2, '0');
  const mi = String(d.getMinutes()).padStart(2, '0');
  return {
    updatedAt: `${yyyy}/${mon}/${dd}`,
    detailTime: `${yyyy}年${mon}月${dd}日 ${hh}:${mi}`
  };
};

/**
 * 微信同款的聊天时间显示：
 * - 今天：HH:mm
 * - 昨天：昨天 HH:mm
 * - 近 7 天（不含今天/昨天）：星期X HH:mm
 * - 同年：M月D日 HH:mm
 * - 跨年：YYYY年M月D日 HH:mm
 */
const formatWeChatChatTimeLabel = (ts?: number, fallbackTime?: string): string => {
  if (typeof ts !== 'number' || !Number.isFinite(ts)) {
    return String(fallbackTime || '').trim();
  }
  const d = new Date(ts);
  const now = new Date();

  const pad2 = (n: number) => String(n).padStart(2, '0');
  const hhmm = `${pad2(d.getHours())}:${pad2(d.getMinutes())}`;

  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
  const dayStart = new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime();
  const dayDiff = Math.round((dayStart - todayStart) / 86400000); // -N（N 天前）

  if (dayDiff === 0) return hhmm;
  if (dayDiff === -1) return `昨天 ${hhmm}`;

  // 过去 2~7 天（不含今天/昨天）-> 显示星期
  if (dayDiff <= -2 && dayDiff >= -7) {
    const week = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'][d.getDay()];
    return `${week} ${hhmm}`;
  }

  // 更久：显示月日（同年）或 年月日（跨年）
  const mon = d.getMonth() + 1;
  const dd = d.getDate();
  if (d.getFullYear() === now.getFullYear()) return `${mon}月${dd}日 ${hhmm}`;
  return `${d.getFullYear()}年${mon}月${dd}日 ${hhmm}`;
};

/** 将备忘录草稿合并写入查手机备忘录存储（与单次生成共用逻辑） */
const mergePhoneInspectMemoDraftsFromApi = (
  roleId: string,
  drafts: GeneratedMemoDraft[],
  existing: PhoneInspectMemoItem[],
  maxAllowedTs: number
) => {
  const activeExisting = existing.filter((m) => !m.deleted);
  const pinnedKeys = new Set(activeExisting.filter((m) => m.pinned).map((m) => normalizeMemoDedupKey(m.title, m.body)));
  const regularKeys = new Set(activeExisting.filter((m) => !m.pinned).map((m) => normalizeMemoDedupKey(m.title, m.body)));
  const newItems: PhoneInspectMemoItem[] = [];
  const newItemsSourceOldIndex: Array<number | null> = [];
  const explicitDeletedOldIds = new Set<string>();

  for (const d of Array.isArray(drafts) ? drafts : []) {
    const op = String((d as any).operation || '').trim().toLowerCase();
    const srcIdxRaw = Number((d as any).sourceOldIndex);
    const sourceOldIndex = Number.isFinite(srcIdxRaw) && srcIdxRaw >= 1 ? Math.floor(srcIdxRaw) : null;
    if (op === 'delete' && sourceOldIndex != null) {
      const targetOld = activeExisting[sourceOldIndex - 1];
      if (targetOld) explicitDeletedOldIds.add(targetOld.id);
      continue;
    }
    const title = String(d.title || '').trim() || '未命名';
    let body = normalizeMemoBodyText(String(d.body || '')).trim() || '';
    const pinned = !!d.pinned;
    const rawTime = d.time;
    const ts = parseMemoTimeToTimestamp(rawTime);
    const validTs = ts != null && ts <= maxAllowedTs ? ts : Math.min(maxAllowedTs, Date.now());
    const { updatedAt, detailTime } = formatMemoDateText(validTs);
    const normalizedPhotoBlock = d.photoBlock
      ? {
          ...d.photoBlock,
          items: Array.isArray(d.photoBlock.items)
            ? d.photoBlock.items.map((it) => {
                const parsed = splitPhotoDescAndThoughts(String(it?.desc || ''));
                if (parsed.thoughts.length > 0) {
                  body = `${body}${body ? '\n' : ''}${parsed.thoughts.map((t) => `想法：${t}`).join('\n')}`.trim();
                }
                return {
                  ...it,
                  desc: parsed.cleanDesc || String(it?.name || '').trim()
                };
              })
            : []
        }
      : undefined;
    const key = normalizeMemoDedupKey(title, body);

    if (pinned && regularKeys.has(key)) continue;
    if (!pinned && pinnedKeys.has(key)) continue;
    if (pinned) pinnedKeys.add(key);
    else regularKeys.add(key);

    newItems.push({
      id: `m-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
      title,
      updatedAt,
      detailTime,
      preview: getMemoPreviewText(body),
      body,
      pinned,
      tableBlock: d.tableBlock,
      photoBlock: normalizedPhotoBlock,
      voiceBlock: d.voiceBlock,
      fileBlock: d.fileBlock
    });
    newItemsSourceOldIndex.push(sourceOldIndex);
  }

  const matchedOldIds = new Set<string>();
  const consumedNewIdx = new Set<number>();
  const nextActive: PhoneInspectMemoItem[] = [];

  newItems.forEach((n, i) => {
    const srcIdx = newItemsSourceOldIndex[i];
    if (srcIdx == null) return;
    const oldItem = activeExisting[srcIdx - 1];
    if (!oldItem) return;
    if (matchedOldIds.has(oldItem.id)) return;
    if (explicitDeletedOldIds.has(oldItem.id)) return;
    consumedNewIdx.add(i);
    matchedOldIds.add(oldItem.id);
    nextActive.push({
      ...n,
      id: oldItem.id,
      deleted: false,
      deletedAt: undefined
    });
  });

  for (const oldItem of activeExisting) {
    const oldKey = normalizeMemoDedupKey(oldItem.title, oldItem.body);
    const idx = newItems.findIndex((n, i) => !consumedNewIdx.has(i) && normalizeMemoDedupKey(n.title, n.body) === oldKey);
    if (idx >= 0) {
      const picked = newItems[idx];
      consumedNewIdx.add(idx);
      matchedOldIds.add(oldItem.id);
      nextActive.push({
        ...picked,
        id: oldItem.id,
        deleted: false,
        deletedAt: undefined
      });
    }
  }

  for (const oldItem of activeExisting) {
    if (matchedOldIds.has(oldItem.id)) continue;
    let bestIdx = -1;
    let bestScore = 0;
    newItems.forEach((n, i) => {
      if (consumedNewIdx.has(i)) return;
      const score = calcMemoBodySimilarity(oldItem.body, n.body);
      if (score > bestScore) {
        bestScore = score;
        bestIdx = i;
      }
    });
    if (bestIdx >= 0 && bestScore >= 0.33) {
      const picked = newItems[bestIdx];
      consumedNewIdx.add(bestIdx);
      matchedOldIds.add(oldItem.id);
      nextActive.push({
        ...picked,
        id: oldItem.id,
        deleted: false,
        deletedAt: undefined
      });
      continue;
    }

    const oldTitleKey = normalizeMemoTitleKey(oldItem.title);
    const titleIdx = newItems.findIndex((n, i) => !consumedNewIdx.has(i) && normalizeMemoTitleKey(n.title) === oldTitleKey);
    if (titleIdx >= 0) {
      const picked = newItems[titleIdx];
      consumedNewIdx.add(titleIdx);
      matchedOldIds.add(oldItem.id);
      nextActive.push({
        ...picked,
        id: oldItem.id,
        deleted: false,
        deletedAt: undefined
      });
    }
  }

  newItems.forEach((n, i) => {
    if (consumedNewIdx.has(i)) return;
    nextActive.push({
      ...n,
      deleted: false,
      deletedAt: undefined
    });
  });

  const deletedItemsFromOld = activeExisting
    .filter((m) => !matchedOldIds.has(m.id))
    .filter((m) => {
      if (explicitDeletedOldIds.has(m.id)) return true;
      let best = 0;
      newItems.forEach((n) => {
        const s = calcMemoBodySimilarity(m.body, n.body);
        if (s > best) best = s;
      });
      return best < 0.26;
    })
    .map((m) => {
      const nowText2 = formatMemoDateText(Date.now());
      return {
        ...m,
        pinned: false,
        deleted: true,
        deletedAt: nowText2.detailTime
      } as PhoneInspectMemoItem;
    });
  const oldDeletedItems = existing.filter((m) => !!m.deleted);

  saveInspectMemos(roleId, [...nextActive, ...deletedItemsFromOld, ...oldDeletedItems]);
};

function buildInspectWechatDataFromApiJson(
  roleId: string,
  role: StoryRole,
  parsed: any,
  now: number
): PhoneInspectWechatGeneratedData | null {
  if (!parsed || !Array.isArray(parsed.chats) || !Array.isArray(parsed.contacts) || !parsed.wallet) {
    return null;
  }
  const emptyFallback: PhoneInspectWechatGeneratedData = {
    roleId,
    chats: [],
    contacts: [],
    wallet: { walletId: '', balance: 0, paymentPassword: '000000', bills: [] }
  };
  const safeChats: PhoneInspectWechatGeneratedChat[] = parsed.chats.slice(0, 16).map((c: any, idx: number) => {
    const messagesRaw = Array.isArray(c?.messages) ? c.messages : [];
    const messages: PhoneInspectWechatGeneratedChatMessage[] = messagesRaw.slice(0, 48).map((m: any, mi: number) =>
      normalizeInspectGeneratedChatMessage(m, String(m?.id || `m-${idx}-${mi}`))
    );
    const last = messages[messages.length - 1];
    return {
      id: String(c?.id || `chat-${idx}`),
      name: String(c?.displayName || c?.name || '联系人').trim(),
      avatarText: String(c?.avatarText || (c?.displayName || c?.name || '联').slice(0, 1)),
      avatarUrl: String(c?.avatarUrl || ''),
      time: String(c?.time || last?.time || ''),
      lastMessage: String(c?.lastMessage || '').trim() || inspectGeneratedLastMessagePreview(last) || '',
      unread: Math.max(0, Number(c?.unread || 0)),
      messages
    };
  });
  const safeContacts: PhoneInspectWechatGeneratedContact[] = parsed.contacts.slice(0, 30).map((c: any, idx: number) => {
    const displayName = String(c?.displayName || c?.name || '联系人').trim();
    return {
      id: String(c?.id || `contact-${idx}`),
      name: displayName,
      avatarText: String(c?.avatarText || displayName.slice(0, 1) || '联'),
      avatarUrl: String(c?.avatarUrl || ''),
      boundRoleId: c?.boundRoleId ? String(c.boundRoleId) : undefined,
      source: c?.source === 'bound-npc' ? 'bound-npc' : 'unbound-new'
    };
  });
  const wallet = parsed.wallet || {};
  const billsRaw = Array.isArray(wallet.bills) ? wallet.bills : [];
  const safeBills: PhoneInspectWechatGeneratedWalletBill[] = billsRaw.slice(0, 20).map((b: any, idx: number) => ({
    id: String(b?.id || `bill-${idx}`),
    title: String(b?.title || '账单'),
    amount: Number(b?.amount || 0),
    time: String(b?.time || '')
  }));

  let nextInspectWechat: PhoneInspectWechatGeneratedData = {
    roleId,
    chats: safeChats.length ? safeChats : emptyFallback.chats,
    contacts: safeContacts.length ? safeContacts : emptyFallback.contacts,
    wallet: {
      walletId: String(wallet.walletId || `wallet_${roleId.slice(0, 6)}_${String(now).slice(-6)}`),
      balance: Number(wallet.balance || 0),
      paymentPassword: String(wallet.paymentPassword || `${Math.floor(100000 + Math.random() * 900000)}`).slice(0, 6),
      bills: safeBills.length ? safeBills : emptyFallback.wallet.bills
    }
  };
  if (
    getInspectBoundRelations(role).length ||
    nextInspectWechat.contacts.length ||
    nextInspectWechat.chats.length
  ) {
    nextInspectWechat = hydrateInspectWechatGeneratedData(nextInspectWechat);
  }
  return nextInspectWechat;
}

const getDefaultFloatingBallPos = () => {
  try {
    const w = window.innerWidth || 375;
    const h = window.innerHeight || 667;
    return {
      x: Math.max(12, w - 72),
      y: Math.max(120, h - 260)
    };
  } catch {
    return { x: 300, y: 420 };
  }
};

const loadWeChatFloatingBallSettings = (): WeChatFloatingBallSettings => {
  const allowed: WeChatFloatingBallAction[] = [
    'photo',
    'video-call',
    'red-packet',
    'transfer',
    'location',
    'inspect-phone',
    'regenerate',
    'auto-reply',
    'my-identity',
    'heart-talk',
    'continue-reply',
    'mark-read-no-reply',
    'mark-unread'
  ];
  const fallback: WeChatFloatingBallSettings = {
    enabled: false,
    pos: getDefaultFloatingBallPos(),
    actions: ['red-packet', 'regenerate', 'auto-reply']
  };
  try {
    const raw = appStorage.getItem(WECHAT_FLOATING_BALL_SETTINGS_KEY);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw) as Partial<WeChatFloatingBallSettings>;
    const enabled = !!parsed.enabled;
    const pos =
      parsed.pos &&
        typeof parsed.pos === 'object' &&
        typeof (parsed.pos as any).x === 'number' &&
        typeof (parsed.pos as any).y === 'number'
        ? { x: (parsed.pos as any).x, y: (parsed.pos as any).y }
        : fallback.pos;
    const actionsRaw = Array.isArray(parsed.actions)
      ? (parsed.actions.filter(Boolean) as string[])
      : fallback.actions;
    const actions = actionsRaw.filter((k) => allowed.includes(k as WeChatFloatingBallAction)) as WeChatFloatingBallAction[];
    return { enabled, pos, actions: actions.length ? actions : fallback.actions };
  } catch {
    return fallback;
  }
};

const saveWeChatFloatingBallSettings = (settings: WeChatFloatingBallSettings) => {
  try {
    appStorage.setItem(WECHAT_FLOATING_BALL_SETTINGS_KEY, JSON.stringify(settings));
  } catch {
    // ignore
  }
};

// 加载聊天消息（同步返回：先用 localStorage 快照 + 内存缓存，随后异步用 IndexedDB 补全）
const loadChatMessages = (chatId: string): ChatMessage[] => {
  if (!chatId) return [];

  // 1）优先走内存缓存（同步）
  // 注意：返回数组的副本，避免外部直接修改缓存导致数据不一致
  if (Array.isArray(chatMessagesCache[chatId])) {
    const cached = chatMessagesCache[chatId]!;
    
    // 即使缓存存在，也要异步检查 IndexedDB 是否有更新（确保数据一致性）
    // 但只在"还没拉过"或"距离上次检查超过一定时间"时检查，避免频繁查询
    const st = chatMessagesIdbLoadState[chatId] || 'idle';
    const lastCheckKey = `idb-check-${chatId}`;
    const lastCheckTime = (window as any)[lastCheckKey] || 0;
    const now = Date.now();
    const CHECK_INTERVAL = 2000; // 2秒内最多检查一次
    
    if (st === 'idle' && (now - lastCheckTime > CHECK_INTERVAL)) {
      chatMessagesIdbLoadState[chatId] = 'loading';
      (window as any)[lastCheckKey] = now;
      void idbGetChatMessages(chatId)
        .then((full) => {
          chatMessagesIdbLoadState[chatId] = 'loaded';
          if (full && Array.isArray(full)) {
            const upgraded = upgradeChatMessages(full);
            const cur = chatMessagesCache[chatId] || [];
            // 如果 IndexedDB 中的数据更完整，更新缓存
            if (upgraded.length > cur.length) {
              chatMessagesCache[chatId] = upgraded;
              dispatchChatMessagesUpdated(chatId);
              console.log(`[WeChatApp] 从 IndexedDB 补全消息，缓存: ${cur.length} -> ${upgraded.length} 条，chatId: ${chatId}`);
            }
          }
        })
        .catch(() => {
          chatMessagesIdbLoadState[chatId] = 'loaded';
        });
    }
    
    return [...cached];
  }

  // 2）读取快照（同步；底层为 IndexedDB KV + 内存缓存）
  let snapshot: ChatMessage[] = [];
  try {
    const raw = appStorage.getItem(`${CHAT_MESSAGES_KEY_PREFIX}${chatId}`);
    if (raw) {
      const parsed = JSON.parse(raw);
      snapshot = upgradeChatMessages(parsed);
    }
  } catch {
    snapshot = [];
  }

  chatMessagesCache[chatId] = snapshot;

  // 3）如果 localStorage 里还残留"老版本整段消息"，做一次增量迁移到 IndexedDB，然后把 localStorage 压到快照大小
  try {
    if (snapshot.length > CHAT_MESSAGES_LS_SNAPSHOT_LIMIT) {
      const full = snapshot;
      // 异步写入 IndexedDB（不阻塞 UI）
      void idbPutChatMessages(chatId, full).then(() => {
        // 写入成功后，把 localStorage 缩成快照；如果 localStorage 已满导致 setItem 失败，则直接 removeItem 释放空间
        // （不会丢历史：完整历史已经进 IndexedDB）
        try {
          const trimmed = full.slice(-CHAT_MESSAGES_LS_SNAPSHOT_LIMIT);
          appStorage.setItem(
            `${CHAT_MESSAGES_KEY_PREFIX}${chatId}`,
            JSON.stringify(trimmed)
          );
        } catch {
          try {
            appStorage.removeItem(`${CHAT_MESSAGES_KEY_PREFIX}${chatId}`);
          } catch {
            // ignore
          }
        }
        // cache 保持 full（用户本轮就能看到完整历史）
        chatMessagesCache[chatId] = full;
        dispatchChatMessagesUpdated(chatId);
      });
    }
  } catch {
    // ignore
  }

  // 4）异步从 IndexedDB 拉取完整历史补全（如果还没拉过）
  const st = chatMessagesIdbLoadState[chatId] || 'idle';
  if (st === 'idle') {
    chatMessagesIdbLoadState[chatId] = 'loading';
    void idbGetChatMessages(chatId)
      .then((full) => {
        chatMessagesIdbLoadState[chatId] = 'loaded';
        if (full && Array.isArray(full)) {
          const upgraded = upgradeChatMessages(full);
          const cur = chatMessagesCache[chatId] || [];
          // 只在"更完整"时覆盖，避免短快照把长历史覆盖回去
          if (upgraded.length > cur.length) {
            chatMessagesCache[chatId] = upgraded;
            dispatchChatMessagesUpdated(chatId);
            console.log(`[WeChatApp] 从 IndexedDB 加载完整历史，快照: ${cur.length} -> ${upgraded.length} 条，chatId: ${chatId}`);
          }
        }
      })
      .catch(() => {
        chatMessagesIdbLoadState[chatId] = 'loaded';
      });
  }

  return snapshot;
};

/** 单条消息在会话列表 / 系统推送中的预览文案（语音与表情包不展示正文或时长） */
const getSingleMessageListPreview = (last: ChatMessage | any): string => {
  let preview = String(last?.text || '');

  if (typeof last?.redPacketAmount === 'number' && last.redPacketAmount > 0) {
    const note = last.redPacketNote || preview.replace(/^\[红包\]\s*/u, '').trim();
    return `[Lumi红包]${note || '点开看看'}`;
  }
  if ((last as any).voiceCallRecord) {
    return '[语音通话]';
  }
  if (last?.voiceDuration) {
    return '[语音]';
  }
  if (last?.emojiName) {
    return '[动画表情]';
  }
  if ((last as any).imagePreviewUrl) {
    return '[图片]';
  }
  return preview;
};

// 从聊天记录中获取最近一条用于会话列表显示的预览文案、时间和时间戳
const getLastMessagePreview = (chatId: string) => {
  const messages = loadChatMessages(chatId);
  if (!messages.length) {
    return { lastMessage: '', time: '', ts: 0 };
  }
  // 过滤掉系统消息，只看双方聊天内容；如果全是系统消息，就退回到最后一条任意消息
  const normalMessages = messages.filter(
    (m) => m.from === 'self' || m.from === 'other'
  );
  const source = normalMessages.length ? normalMessages : messages;
  const last = source[source.length - 1];

  const preview = getSingleMessageListPreview(last);

  const ts =
    typeof (last as any).timestamp === 'number' && Number.isFinite((last as any).timestamp)
      ? (last as any).timestamp as number
      : Date.now();

  return { lastMessage: preview, time: last.time, ts };
};

// 去掉昵称中的备注括号，只保留主昵称
// 例如："抽抽子（A亲爱的杨🐑8.31）" => "抽抽子"
const getBaseNickname = (name?: string | null): string => {
  if (!name) return '';
  const idx = name.indexOf('（');
  return idx >= 0 ? name.slice(0, idx) : name;
};

// 从世界书文本中解析“世界观当前时间”
// 约定：只有世界书里明确写了当前世界时间，才允许卡片时间超过系统时间（但不允许超过该世界观时间上限）
const parseWorldbookNowTimestamp = (text: string | null | undefined): number | null => {
  const s = String(text || '').trim();
  if (!s) return null;

  // 支持示例：
  // - 【世界观当前时间】2099-05-12 17:30
  // - 世界观当前时间：2099/5/12 17:30
  // - 世界观时间: 2099-05-12
  const m = s.match(
    /(?:【世界观当前时间】|世界观当前时间[:：]|世界观时间[:：]|当前世界时间[:：])\s*(\d{4})[\/\-.](\d{1,2})[\/\-.](\d{1,2})(?:\s+(\d{1,2})[:：](\d{2}))?/u
  );
  if (!m) return null;
  const yyyy = Number(m[1]);
  const mon = Number(m[2]);
  const dd = Number(m[3]);
  const hh = Number(m[4] ?? '0');
  const mi = Number(m[5] ?? '0');
  if (![yyyy, mon, dd, hh, mi].every(Number.isFinite)) return null;
  const ts = new Date(yyyy, mon - 1, dd, hh, mi, 0, 0).getTime();
  return Number.isFinite(ts) ? ts : null;
};

// 计算“某个角色允许的最大时间戳上限”
// - 默认：不允许未来，maxTs = fallbackNow（系统时间）
// - 若世界书明确给出【世界观当前时间】，则 maxTs = worldNowTs（允许超过系统时间，但不超过世界观当前时间）
const getMaxAllowedTimestampForRole = (role: any, fallbackNow: number): number => {
  try {
    const wbs = ((role as any)?.worldbooks || []).filter((wb: any) => wb?.enabled !== false);
    if (!Array.isArray(wbs) || wbs.length === 0) return fallbackNow;
    for (const wb of wbs) {
      const entries = ((wb as any)?.entries || []).filter((e: any) => e?.enabled !== false);
      if (!Array.isArray(entries)) continue;
      for (const e of entries) {
        const ts = parseWorldbookNowTimestamp((e as any)?.content);
        if (typeof ts === 'number' && Number.isFinite(ts) && ts > 0) {
          return ts;
        }
      }
    }
  } catch {
    // ignore
  }
  return fallbackNow;
};

// 保存聊天消息：完整历史存 IndexedDB；localStorage 只存最近快照，避免配额爆仓
const saveChatMessages = (chatId: string, messages: ChatMessage[]) => {
  if (!chatId) return;

  const allMessages = Array.isArray(messages) ? messages : [];
  // 修复：若“清空聊天记录”的显示偏移残留且大于当前真实长度，会导致后续新消息被全部 slice 掉而看不见。
  // 在保存消息时同步纠正该偏移（仅影响前端展示，不影响真实聊天内容）。
  try {
    const cleared = getChatClearCount(chatId);
    if (cleared > 0 && cleared > allMessages.length) {
      setChatClearCount(chatId, 0);
    }
  } catch {
    // ignore
  }
  
  // 1）更新内存缓存（同步，限制大小避免内存压力）
  const safe =
    allMessages.length > MAX_CHAT_MESSAGES_PER_CHAT
      ? allMessages.slice(-MAX_CHAT_MESSAGES_PER_CHAT)
      : allMessages;
  chatMessagesCache[chatId] = safe;

  // 2）写快照（同步，尽量小；底层为 IndexedDB KV + 内存缓存）
  try {
    const snapshot = allMessages.slice(-CHAT_MESSAGES_LS_SNAPSHOT_LIMIT);
    appStorage.setItem(
      `${CHAT_MESSAGES_KEY_PREFIX}${chatId}`,
      JSON.stringify(snapshot)
    );
  } catch {
    // ignore
  }

  // 3）异步写入 IndexedDB（完整历史，不要截断）
  // 重要：IndexedDB 存储完整历史，确保聊天记录管理页面能看到所有消息
  void idbPutChatMessages(chatId, allMessages).then(() => {
    // 写入成功后，如果 IndexedDB 中的数据比缓存更完整，更新缓存
    void idbGetChatMessages(chatId).then((idbMessages) => {
      if (idbMessages && Array.isArray(idbMessages) && idbMessages.length > safe.length) {
        const upgraded = upgradeChatMessages(idbMessages);
        // 更新缓存为完整数据（但限制在 MAX_CHAT_MESSAGES_PER_CHAT 内）
        const cacheData = upgraded.length > MAX_CHAT_MESSAGES_PER_CHAT
          ? upgraded.slice(-MAX_CHAT_MESSAGES_PER_CHAT)
          : upgraded;
        chatMessagesCache[chatId] = cacheData;
        dispatchChatMessagesUpdated(chatId);
        console.log(`[WeChatApp] IndexedDB 数据已同步，缓存更新为 ${cacheData.length} 条（完整历史 ${idbMessages.length} 条），chatId: ${chatId}`);
      }
    });
  });

  dispatchChatMessagesUpdated(chatId);
};

// 删除某个会话最近 N 条聊天消息（只影响原始聊天记录，不动记忆快照）
const deleteRecentChatMessages = (chatId: string, count: number = 50) => {
  try {
    if (!chatId || count <= 0) return;
    const all = loadChatMessages(chatId);
    if (!Array.isArray(all) || all.length === 0) return;
    const n = Math.max(1, Math.min(count, all.length));
    const kept = all.slice(0, all.length - n);
    saveChatMessages(chatId, kept);
  } catch (err) {
    console.error('删除最近聊天消息失败:', err);
  }
};

// 按消息 ID 列表删除聊天消息（支持手动多选删除）
const deleteChatMessagesByIds = (chatId: string, ids: string[]) => {
  try {
    if (!chatId || !Array.isArray(ids) || ids.length === 0) return;
    const toDelete = new Set(ids);
    const all = loadChatMessages(chatId);
    if (!Array.isArray(all) || all.length === 0) return;
    const kept = all.filter((m) => !toDelete.has(m.id));
    saveChatMessages(chatId, kept);
  } catch (err) {
    console.error('按 ID 删除聊天消息失败:', err);
  }
};

