// 根据消息记录与最后阅读时间计算该会话的未读消息数量（仅统计对方发来的消息）
const getUnreadCountForChat = (chatId: string): number => {
  const messages = loadChatMessages(chatId);
  if (!messages.length) return 0;

  const lastReadTs = loadChatLastReadTimestamp(chatId);

  // 防抖动：按 message.id 去重，避免异步补全/多源写入导致短暂重复计数
  const uniqueMessages = (() => {
    const seen = new Set<string>();
    const out: ChatMessage[] = [];
    for (const m of messages) {
      const id = String((m as any)?.id || '').trim();
      if (!id) continue;
      if (seen.has(id)) continue;
      seen.add(id);
      out.push(m);
    }
    return out.length ? out : messages;
  })();

  // 如果还从未记录过阅读时间（例如新会话或老数据升级前），默认把所有对方发来的消息视为“未读”
  if (!lastReadTs) {
    return uniqueMessages.reduce((count, m) => {
      if (m.from === 'other') {
        return count + 1;
      }
      return count;
    }, 0);
  }

  return uniqueMessages.reduce((count, m) => {
    if (m.from === 'other' && typeof m.timestamp === 'number' && m.timestamp > lastReadTs) {
      return count + 1;
    }
    return count;
  }, 0);
};

