/** 从主回复文本中剥离语音来电 / 共同好友链标记（在拆弹幕、心语之前调用） */
const parseWeChatAuxiliaryMarkers = (
  raw: string,
  opts: { voiceEnabled: boolean; mutualEnabled: boolean }
): { text: string; autoVoiceCallIntent?: boolean; mutualFriendSideEffects?: MutualFriendChainPayload | null } => {
  let text = String(raw || '').trim();
  let autoVoiceCallIntent: boolean | undefined;
  let mutualFriendSideEffects: MutualFriendChainPayload | null = null;

  if (opts.voiceEnabled) {
    const re = /<<AUTO_VOICE_CALL:(true|false)>>/gi;
    const matches = [...text.matchAll(re)];
    if (matches.length) {
      const last = matches[matches.length - 1];
      if (last && last[1]) {
        autoVoiceCallIntent = last[1].toLowerCase() === 'true';
      }
      text = text.replace(re, '').trim();
    }
  }

  if (opts.mutualEnabled) {
    const open = text.indexOf('<<MUTUAL_FRIEND_CHAIN>>');
    const close = text.indexOf('<<END_MUTUAL_FRIEND_CHAIN>>');
    if (open !== -1 && close !== -1 && close > open) {
      const jsonStr = text.slice(open + '<<MUTUAL_FRIEND_CHAIN>>'.length, close).trim();
      text = `${text.slice(0, open)}\n${text.slice(close + '<<END_MUTUAL_FRIEND_CHAIN>>'.length)}`.trim();
      try {
        mutualFriendSideEffects = JSON.parse(jsonStr) as MutualFriendChainPayload;
      } catch {
        mutualFriendSideEffects = null;
      }
    }
  }

  return { text, autoVoiceCallIntent, mutualFriendSideEffects };
};

/** 从主回复末尾剥离 <<WECHAT_MOMENTS>>…<<END_WECHAT_MOMENTS>>（与线上回复同一次 completion）；支持单对象或数组（群聊多成员） */
const parseWeChatMomentsMarker = (
  raw: string,
  defaultRoleId: string
): {
  text: string;
  items: Array<{ roleId: string; shouldPost: boolean; text: string; location: string }>;
} => {
  let text = String(raw || '').trim();
  const items: Array<{ roleId: string; shouldPost: boolean; text: string; location: string }> = [];
  const open = text.indexOf('<<WECHAT_MOMENTS>>');
  const close = text.indexOf('<<END_WECHAT_MOMENTS>>');
  if (open !== -1 && close !== -1 && close > open) {
    let jsonStr = text.slice(open + '<<WECHAT_MOMENTS>>'.length, close).trim();
    text = `${text.slice(0, open)}\n${text.slice(close + '<<END_WECHAT_MOMENTS>>'.length)}`.trim();
    if (jsonStr.startsWith('```')) {
      jsonStr = jsonStr.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
    }
    try {
      const p = JSON.parse(jsonStr) as any;
      const pushOne = (o: any) => {
        if (!o || typeof o !== 'object') return;
        const rid = String(o.roleId ?? defaultRoleId).trim() || defaultRoleId;
        items.push({
          roleId: rid,
          shouldPost: o.shouldPost === true,
          text: String(o.text ?? '').trim(),
          location: String(o.location ?? '').trim()
        });
      };
      if (Array.isArray(p)) {
        p.forEach(pushOne);
      } else {
        pushOne(p);
      }
    } catch {
      // ignore
    }
  }
  return { text, items };
};

