// 添加传话记录
const addRelayRecord = (fromRoleId: string, toRoleId: string, relayedMessage: string, chatId: string) => {
  const record: RelayRecord = {
    id: `relay-${Date.now()}-${Math.random()}`,
    fromRoleId,
    toRoleId,
    relayedMessage,
    timestamp: Date.now(),
    chatId
  };

  // 保存到传话发起者的记录中
  const fromRecords = loadRelayRecords(fromRoleId);
  fromRecords.push(record);
  saveRelayRecords(fromRoleId, fromRecords);

  // 保存到传话接收者的记录中
  const toRecords = loadRelayRecords(toRoleId);
  toRecords.push(record);
  saveRelayRecords(toRoleId, toRecords);

  console.log('[WeChatApp] 已保存传话记录:', record);
};

// 共同好友：仅应用主回复里解析出的 JSON，不发起任何额外模型请求
const applyMutualFriendChainFromMainReply = async (
  payload: MutualFriendChainPayload | null | undefined,
  currentRoleId: string,
  currentRole: StoryRole,
  setChatsFn: React.Dispatch<React.SetStateAction<any[]>>,
  setChatMessagesKeyFn: React.Dispatch<React.SetStateAction<number>>,
  getLastMessagePreviewFn: (chatId: string) => { lastMessage: string; time: string },
  getUnreadCountForChatFn: (chatId: string) => number,
  activeTabRefFn: React.MutableRefObject<string>,
  activeChatIdRefFn: React.MutableRefObject<string | null>,
  scrollToBottomFn: () => void,
  setNewMessageToastFn: (toast: any) => void
): Promise<void> => {
  if (!payload) return;

  const relSet = new Set(
    (currentRole.relations || []).map((r) => String(r.otherRoleId || '').trim()).filter(Boolean)
  );
  if (!relSet.size) return;

  const allRoles = loadStoryRoles();
  const sourceChatId = `chat-${currentRoleId}`;

  for (const r of payload.relayTo || []) {
    const oid = String(r?.otherRoleId || '').trim();
    const msg = String(r?.relayedMessage || '').trim();
    if (!oid || !relSet.has(oid) || !msg) continue;
    addRelayRecord(currentRoleId, oid, msg, sourceChatId);
  }

  for (const og of payload.otherOutgoing || []) {
    const oid = String(og?.otherRoleId || '').trim();
    if (!oid || !relSet.has(oid)) continue;
    const lines = (og.lines || []).map((x) => String(x || '').trim()).filter(Boolean);
    if (!lines.length) continue;

    const otherRole = allRoles.find((rr) => rr.id === oid);
    if (!otherRole) continue;

    await new Promise((res) => setTimeout(res, 800));

    const otherChatId = `chat-${oid}`;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const charCount = line.length || 1;
      const blocks = Math.max(1, Math.ceil(charCount / 6));
              const delayMs = blocks * 1000;
              if (delayMs > 0) {
        // eslint-disable-next-line no-await-in-loop
        await new Promise((resolve) => setTimeout(resolve, delayMs));
              }

      const replyTime = new Date().toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
              const nowTimestamp = Date.now();
              const maxAllowedTsForMessage = getMaxAllowedTimestampForRole(otherRole as any, nowTimestamp);
              const safeMessageTimestamp =
        typeof nowTimestamp === 'number' ? Math.min(nowTimestamp, maxAllowedTsForMessage) : nowTimestamp;

              const newMessage: ChatMessage = {
        id: `mutual-chain-${nowTimestamp}-${i}-${Math.random().toString(16).slice(2)}`,
                from: 'other',
        text: line,
                time: replyTime,
        timestamp: safeMessageTimestamp
      };

              const currentMessages = loadChatMessages(otherChatId);
              currentMessages.push(newMessage);
              saveChatMessages(otherChatId, currentMessages);
              setChatMessagesKeyFn((prev) => prev + 1);

              const isOnThisChatNow =
        activeTabRefFn.current === 'chat' && activeChatIdRefFn.current === otherChatId;

              if (!isOnThisChatNow) {
        const previewText = newMessage.text || '';
        setChatsFn((prev) =>
          prev.map((chat) => {
                    if (chat.id !== otherChatId) return chat;
                    const { lastMessage, time: lastTime } = getLastMessagePreviewFn(otherChatId);
                    const unread = getUnreadCountForChatFn(otherChatId);
                    return {
                      ...chat,
                      lastMessage: previewText || chat.lastMessage,
                      time: lastTime,
                      unread
                    };
          })
        );

                try {
                  const contactsForToast = loadWeChatContacts();
                  const rolesForToast = loadStoryRoles();
          const matchedRole = rolesForToast.find((rr) => rr.id === otherRole.id);
                  const contactForToast = matchedRole
            ? contactsForToast.find((c) => c.roleId === matchedRole.id)
                    : null;
                  const displayName =
                    contactForToast?.remark ||
                    matchedRole?.wechatNickname ||
                    matchedRole?.name ||
                    '对方';
                  const avatarUrlForToast = matchedRole?.avatarUrl;

                  setNewMessageToastFn({
                    chatId: otherChatId,
                    roleName: displayName,
                    avatarUrl: avatarUrlForToast,
                    text: previewText,
                    time: replyTime
                  });
                } catch {
          // ignore
                }
              } else {
                scrollToBottomFn();
              }
            }
  }
};

