const ANONYMOUS_QA_INITIAL_QUESTIONS: AnonymousQaQuestion[] = [];

const ANONYMOUS_QA_INITIAL_ANSWERS: AnonymousQaAnswer[] = [];

const ANONYMOUS_QA_INITIAL_COMMENTS: AnonymousQaComment[] = [];

const ANONYMOUS_QA_STORAGE_KEY = 'mini-ai-phone.anonymous-qa-state-v1';

type AnonymousQaPersistedSnapshot = {
  questions: AnonymousQaQuestion[];
  answers: AnonymousQaAnswer[];
  comments: AnonymousQaComment[];
  plazaVisibleCount: number;
};

/** 首屏同步读入，避免「hydrate 的 setState 尚未合并时 save effect 先跑」把空数据写回存储 */
let anonymousQaPersistedSnapshotMemo: AnonymousQaPersistedSnapshot | null = null;

function getAnonymousQaPersistedSnapshot(): AnonymousQaPersistedSnapshot {
  if (anonymousQaPersistedSnapshotMemo) return anonymousQaPersistedSnapshotMemo;
  try {
    const raw = appStorage.getItem(ANONYMOUS_QA_STORAGE_KEY);
    if (!raw) {
      anonymousQaPersistedSnapshotMemo = {
        questions: ANONYMOUS_QA_INITIAL_QUESTIONS,
        answers: ANONYMOUS_QA_INITIAL_ANSWERS,
        comments: ANONYMOUS_QA_INITIAL_COMMENTS,
        plazaVisibleCount: 10,
      };
      return anonymousQaPersistedSnapshotMemo;
    }
    const p = JSON.parse(raw) as Partial<{
      questions: AnonymousQaQuestion[];
      answers: AnonymousQaAnswer[];
      comments: AnonymousQaComment[];
      plazaVisibleCount: number;
    }>;
    anonymousQaPersistedSnapshotMemo = {
      questions: Array.isArray(p.questions) ? p.questions : ANONYMOUS_QA_INITIAL_QUESTIONS,
      answers: Array.isArray(p.answers) ? p.answers : ANONYMOUS_QA_INITIAL_ANSWERS,
      comments: Array.isArray(p.comments) ? p.comments : ANONYMOUS_QA_INITIAL_COMMENTS,
      plazaVisibleCount:
        typeof p.plazaVisibleCount === 'number' &&
        Number.isFinite(p.plazaVisibleCount) &&
        p.plazaVisibleCount >= 1
          ? Math.floor(p.plazaVisibleCount)
          : 10,
    };
    return anonymousQaPersistedSnapshotMemo;
  } catch {
    anonymousQaPersistedSnapshotMemo = {
      questions: ANONYMOUS_QA_INITIAL_QUESTIONS,
      answers: ANONYMOUS_QA_INITIAL_ANSWERS,
      comments: ANONYMOUS_QA_INITIAL_COMMENTS,
      plazaVisibleCount: 10,
    };
    return anonymousQaPersistedSnapshotMemo;
  }
}

// 好友申请相关类型
type FriendRequest = {
  id: string;
  roleId: string;
  greeting: string; // 打招呼消息
  remark?: string; // 备注
  tags?: string; // 标签
  permission: 'all' | 'chat-only'; // 朋友权限：all=聊天、朋友圈等，chat-only=仅聊天
  hideMyMoments?: boolean; // 不给ta看我的朋友圈和状态
  hideTheirMoments?: boolean; // 不看ta的朋友圈和聊天
  status: 'pending' | 'accepted' | 'rejected'; // 申请状态
  timestamp: number; // 申请时间
};

// 玩家身份（和线下故事 StoryApp 中的玩家身份结构保持一致）
type PlayerIdentity = {
  name: string;
  // 别名 / 小名（可选）
  alias?: string;
  gender: 'male' | 'female' | 'other' | '';
  // 玩家年龄（可选，用于让角色更好理解你是怎样的玩家）
  age?: number | null;
  // MBTI 人格类型（可选，例如：INFP / ENTJ）
  mbti?: string;
  intro: string;
  tags: string; // 职业
  interests?: string; // 兴趣（多个用逗号分隔）
  dealbreakers?: string; // 雷点（多个用逗号分隔）
  // 联系方式
  phoneNumber?: string; // 10位手机号
  wechatId?: string; // 微信号
  // 玩家世界书（在微信侧只做透传，不强校验结构）
  worldbooks?: any[];
  // 兼容微信侧使用的微信昵称字段：优先使用 name
  wechatNickname?: string;
};

// 微信侧「我」页使用的独立个人资料（与 StoryApp 中的玩家身份解耦）
type WeChatSelfProfile = {
  nickname: string;
  gender: 'male' | 'female' | 'other' | '';
  region: string;
  wechatId?: string;
  pokeText?: string;
  intro?: string;
  avatarUrl?: string;
  // 文字版头像描述，专门给角色和模型理解头像长什么样用
  avatarDesc?: string;
};

type WeChatWallet = {
  walletId: string;
  balance: number; // 余额（单位：元）
  paymentPassword: string; // 支付密码（加密存储，实际应该加密，这里简化处理）
  createdAt: number; // 创建时间戳
};

