type PlayerIdentityWithId = PlayerIdentity & {
  id: string;
  createdAt: number;
  updatedAt: number;
};

const loadPlayerIdentityList = (): PlayerIdentityWithId[] => {
  try {
    const raw = appStorage.getItem(PLAYER_IDENTITIES_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed as PlayerIdentityWithId[];
  } catch {
    return [];
  }
};

const savePlayerIdentityList = (list: PlayerIdentityWithId[]) => {
  try {
    appStorage.setItem(PLAYER_IDENTITIES_KEY, JSON.stringify(list));
  } catch {
    // ignore
  }
};

type PlayerIdentityUsageMap = Record<string, string[]>; // identityId -> roleId[]

const loadPlayerIdentityUsage = (): PlayerIdentityUsageMap => {
  try {
    const raw = appStorage.getItem(PLAYER_IDENTITY_USAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed)
      ? (parsed as PlayerIdentityUsageMap)
      : {};
  } catch {
    return {};
  }
};

const savePlayerIdentityUsage = (map: PlayerIdentityUsageMap) => {
  try {
    appStorage.setItem(PLAYER_IDENTITY_USAGE_KEY, JSON.stringify(map));
  } catch {
    // ignore
  }
};

// 首次使用多身份功能时，从旧的单一身份配置迁移一份到身份列表里，避免用户已有配置丢失
const ensurePlayerIdentityList = (): PlayerIdentityWithId[] => {
  const existing = loadPlayerIdentityList();
  if (existing.length > 0) return existing;

  const legacy = loadPlayerIdentity();
  const hasLegacy =
    legacy &&
    (legacy.name?.trim() ||
      legacy.intro?.trim() ||
      legacy.tags?.trim() ||
      legacy.phoneNumber?.trim() ||
      legacy.wechatId?.trim());

  if (!hasLegacy) return [];

  const now = Date.now();
  const item: PlayerIdentityWithId = {
    ...legacy,
    id: `${now}-${Math.random().toString(16).slice(2)}`,
    createdAt: now,
    updatedAt: now
  };
  const list = [item];
  savePlayerIdentityList(list);
  return list;
};

