  // 保存记忆编辑：直接覆盖对应快照的 summary（视为玩家手动整理后的最终版本）
  const handleSaveMemoryEdit = React.useCallback(() => {
    if (!viewingMemoryChatId || !viewingMemorySnapshot) return;
    const nextSummary = memoryEditText.trim();
    if (!nextSummary) {
      window.alert('记忆内容不能为空，可以适当精简，但不要留空。');
      return;
    }

    const memories = loadChatMemories(viewingMemoryChatId);
    const targetIndex = memories.findIndex((m) => m.id === viewingMemorySnapshot.id);
    if (targetIndex === -1) {
      return;
    }

    const now = new Date();
    const nowStr = now.toLocaleString('zh-CN', { hour12: false });
    const updated: ChatMemorySnapshot = {
      ...memories[targetIndex],
      summary: nextSummary,
      updatedAt: nowStr
    };

    const nextMemories = [...memories];
    nextMemories[targetIndex] = updated;
    saveChatMemories(viewingMemoryChatId, nextMemories);

    // 同步更新当前视图和概览数据
    setViewingMemorySnapshot(updated);
    setChatMemoryOverview(loadAllChatMemoryOverview());
    setIsEditingMemory(false);
  }, [viewingMemoryChatId, viewingMemorySnapshot, memoryEditText]);

