        if (presetOccupations.includes(tags)) {
          setIdentityFormTags(tags);
          setIdentityFormCustomOccupation('');
        } else if (tags) {
          setIdentityFormTags('其他');
          setIdentityFormCustomOccupation(tags);
        } else {
          setIdentityFormTags('');
          setIdentityFormCustomOccupation('');
        }
        const interestsStr = first.interests || '';
        const presetInterests = ['阅读', '写作', '音乐', '电影', '旅行', '摄影', '绘画', '运动', '美食', '咖啡', '茶艺', '花艺', '手作', '游戏', '追剧', '购物', '宠物', '园艺', '收藏'];
        if (interestsStr) {
          // 支持逗号、顿号、空格分隔
          const interestsArray = interestsStr.split(/[、，,\s]+/).filter(Boolean);
          const presetSelected: string[] = [];
          let customInterest = '';
          interestsArray.forEach(interest => {
            if (presetInterests.includes(interest)) {
              presetSelected.push(interest);
            } else {
              customInterest = interest;
            }
          });
          if (customInterest) {
            setIdentityFormInterests([...presetSelected, '其他']);
            setIdentityFormCustomInterest(customInterest);
          } else {
            setIdentityFormInterests(presetSelected);
            setIdentityFormCustomInterest('');
          }
        } else {
          setIdentityFormInterests([]);
          setIdentityFormCustomInterest('');
        }
        const dealbreakersStr = first.dealbreakers || '';
        const presetDealbreakers = ['抽烟', '酗酒', '赌博', '暴力', '冷暴力', '出轨', '控制欲强', '不尊重隐私', '过度依赖', '情绪不稳定', '不守时', '说谎', '不诚实', '自私', '不负责', '过度消费', '不尊重他人', '缺乏边界感', '过度干涉'];
