  // 删除某个会话最近 50 条聊天消息（仅聊天记录，不影响记忆快照）
  const handleDeleteRecentChatMessagesByChatId = React.useCallback((chatId: string) => {
    deleteRecentChatMessages(chatId, 50);
  }, []);

  // 在“最近 50 条消息”详情页中删除选中的消息
  const handleDeleteSelectedChatHistoryMessages = React.useCallback(() => {
    if (!chatHistoryDetailChatId || chatHistorySelectedMessageIds.length === 0) return;
    deleteChatMessagesByIds(chatHistoryDetailChatId, chatHistorySelectedMessageIds);
    setChatHistorySelectedMessageIds([]);
    // 触发列表刷新
    dispatchChatMessagesUpdated(chatHistoryDetailChatId);
  }, [chatHistoryDetailChatId, chatHistorySelectedMessageIds]);

  // 群聊：退出/删除（仅本地数据）
  const handleExitGroupChat = React.useCallback(() => {
    if (!activeChatId || !activeChatId.startsWith('group-')) return;
    const chatId = activeChatId;

    let groupName = '群聊';
    try {
      const groups = loadWeChatGroupChats();
      const g = groups.find((x) => x && x.id === chatId) || null;
      groupName = String(g?.name || groupName).trim() || groupName;
    } catch {
      // ignore
    }

    if (
      !window.confirm(
        `确定要退出“${groupName}”吗？退出后该群聊会从列表中消失（聊天记录不会删除）。`
      )
    ) {
      return;
    }

    try {
      const groups = loadWeChatGroupChats();
      const next = groups.filter((g) => g && g.id !== chatId);
      saveWeChatGroupChats(next);
    } catch (err) {
      console.error('[WeChatApp] 退出群聊失败:', err);
      alert('退出群聊失败，请稍后重试。');
      return;
    }

    setChats((prev) => {
      const next = prev.filter((c) => c && c.id !== chatId);
      // 如果当前正在查看该群聊，把会话切回到其它会话（或置空）
      if (activeChatId === chatId) {
        setActiveChatId(next[0]?.id ?? null);
      }
      return next;
    });

    setShowChatSettings(false);
    setShowChatRoleSettingsPage(false);
    setChatRoleSettingsDraft(null);
  }, [activeChatId]);

  const handleDeleteGroupChat = React.useCallback(() => {
    if (!activeChatId || !activeChatId.startsWith('group-')) return;
    const chatId = activeChatId;

    let groupName = '群聊';
    try {
      const groups = loadWeChatGroupChats();
      const g = groups.find((x) => x && x.id === chatId) || null;
      groupName = String(g?.name || groupName).trim() || groupName;
    } catch {
      // ignore
    }

    if (!window.confirm(`确定要删除“${groupName}”吗？该操作会删除聊天记录和记忆（不可撤销）。`)) {
      return;
    }

    try {
      // 1）移除群聊条目（让会话列表不再显示）
      const groups = loadWeChatGroupChats();
      const nextGroups = groups.filter((g) => g && g.id !== chatId);
      saveWeChatGroupChats(nextGroups);

      // 2）彻底清理聊天记录与记忆（消息 + 记忆快照 + IndexedDB）
      clearChatMemory(chatId);

      // 3）清理该会话的“聊天设定 / 未读状态 / 清空偏移”等
      appStorage.removeItem(`${CHAT_SETTINGS_KEY_PREFIX}${chatId}`);
      appStorage.removeItem(`${WECHAT_CHAT_LAST_READ_TS_PREFIX}${chatId}`);
      appStorage.removeItem(`${WECHAT_CHAT_CLEAR_COUNT_PREFIX}${chatId}`);

      // 4）清理该会话下收藏的消息（避免孤儿收藏项）
      const favorites = loadWeChatFavorites();
      const nextFavorites = favorites.filter((f) => f.chatId !== chatId);
      saveWeChatFavorites(nextFavorites);
    } catch (err) {
      console.error('[WeChatApp] 删除群聊失败:', err);
      alert('删除群聊失败，请稍后重试。');
      return;
    }

    setChats((prev) => {
      const next = prev.filter((c) => c && c.id !== chatId);
      if (activeChatId === chatId) {
        setActiveChatId(next[0]?.id ?? null);
      }
      return next;
    });

    setShowChatSettings(false);
    setShowChatRoleSettingsPage(false);
    setChatRoleSettingsDraft(null);
  }, [activeChatId]);
  // 好友申请页面状态
  const [showFriendRequest, setShowFriendRequest] = React.useState(false);
