          const otherName = other?.wechatNickname || other?.name || rel.otherRoleId || '未知';
          const lab = String(rel.customLabel || '').trim();
          const head = lab ? `${otherName}（关系：${lab}）` : otherName;
          const note = String(rel.note || '').trim();
