                    <button type="button" className="story-btn secondary" style={{ fontSize: 11, padding: '2px 8px' }} onClick={() => setCreateRoleInterestsCollapsed((v) => !v)}>{createRoleInterestsCollapsed ? '展开' : '折叠'}</button>
