                            <button type="button" onClick={() => setPhoneInspectActiveSectionId(null)} style={{ border: 'none', background: 'transparent', color: '#111827', fontSize: 16, padding: '6px 2px', cursor: 'pointer' }}>‹</button>
                            <button
